const CHAPITRES_PREMIERE_SVT: ChapitreData[] = [
  {
    id:'adn-genome-premiere-svt', numero:1,
    titre:'Transmission, variation & expression du patrimoine génétique',
    sousTitre:'ADN · Réplication · Mutations · Transcription · Traduction · Code génétique',
    icon:'🧬', color:'#10b981',
    notions:['ADN','Réplication','Mutation','Transcription','Traduction','Code génétique'],
    exercices:[
      {id:'P1-01',difficulte:1,titre:'Structure de l\'ADN',enonce:'1. Unité de base de l\'ADN ?\n2. 4 bases azotées et appariements.\n3. Complémentarité des bases.',correction:'1. Nucléotide (phosphate + désoxyribose + base)\n2. A-T (2 liaisons H) et G-C (3 liaisons H)\n3. A avec T · G avec C → brins antiparallèles',notions:['ADN']},
      {id:'P1-02',difficulte:1,titre:'Brin complémentaire',enonce:'Brin : 5\'-ATGCGATC-3\'\nÉcrire le brin complémentaire avec son orientation.',correction:'3\'-TACGCTAG-5\'\nOu : 5\'-GATCGCAT-3\'',notions:['Complémentarité']},
      {id:'P1-03',difficulte:1,titre:'Composition en bases',enonce:'ADN : 30% d\'adénine.\nCalculer les % de T, G et C.',correction:'%T = 30% · %G = %C = 20%\n(100 - 30 - 30 = 40% → 20% chacun)',notions:['Chargaff']},
      {id:'P1-04',difficulte:1,titre:'Réplication semi-conservative',enonce:'1. Définir réplication.\n2. Pourquoi semi-conservative ?\n3. Enzyme principale.',correction:'1. Duplication ADN avant division cellulaire\n2. Chaque molécule fille conserve 1 brin parental + 1 néosynthétisé\n3. ADN polymérase',notions:['Réplication']},
      {id:'P1-05',difficulte:1,titre:'Transcription — ARNm',enonce:'Brin matrice : 3\'-TACGGATCGAAT-5\'\n1. Écrire la séquence ARNm.\n2. Quelle base remplace la thymine dans l\'ARN ?',correction:'1. ARNm 5\'→3\' : AUGCCUAGCUUA\n2. L\'uracile (U) remplace la thymine (T)',notions:['Transcription']},
      {id:'P1-06',difficulte:2,titre:'Traduction et code génétique',enonce:'ARNm : 5\'-AUG-GGA-UUU-CAG-UAG-3\'\nCode : GGA=Gly · UUU=Phe · CAG=Gln · UAG=Stop\nDéterminer la séquence protéique.',correction:'AUG=Met · GGA=Gly · UUU=Phe · CAG=Gln · UAG=Stop\nProtéine : Met-Gly-Phe-Gln',notions:['Traduction']},
      {id:'P1-07',difficulte:2,titre:'Types de mutations',enonce:'Normale : ATG-GCA-TGC-AAT\nMutation A : ATG-GCG-TGC-AAT\nMutation B : ATG-G_A-TGC-AAT (délétion C)\n1. Type de chaque mutation.\n2. Laquelle est la plus grave ?',correction:'A : substitution → GCA et GCG = Alanine → silencieuse\nB : délétion → décalage cadre lecture → grave (protéine non fonctionnelle)',notions:['Mutations']},
      {id:'P1-08',difficulte:2,titre:'Agents mutagènes',enonce:'1. 3 types d\'agents mutagènes.\n2. Comment UV induisent-ils des mutations.\n3. Application médicale.',correction:'1. Physique (UV, rayons X) · Chimique (benzène) · Biologique (VPH)\n2. UV → dimères de thymine → erreurs de réplication\n3. Crème solaire → prévention mélanome',notions:['Agents mutagènes']},
      {id:'P1-09',difficulte:2,titre:'Dogme central de la biologie',enonce:'Résumer en 4 étapes le chemin de l\'information génétique.',correction:'1. Réplication : ADN → ADN\n2. Transcription : ADN → ARNm (noyau)\n3. Maturation : épissage des introns\n4. Traduction : ARNm → protéine (ribosomes)',notions:['Dogme central']},
      {id:'P1-10',difficulte:2,titre:'Propriétés du code génétique',enonce:'1. Combien de codons existent ?\n2. Combien codent un AA ?\n3. Définir : dégénéré · universel · non ambigu.',correction:'1. 4³ = 64 codons\n2. 61 codons (3 = stop : UAA, UAG, UGA)\n3. Dégénéré : plusieurs codons → même AA. Universel : commun à tous. Non ambigu : 1 codon = 1 seul AA',notions:['Code génétique']},
      {id:'P1-11',difficulte:2,titre:'Réplication — calcul',enonce:'ADN 2400 pb. Après 3 cycles :\n1. Nombre de molécules.\n2. Nucléotides synthétisés.',correction:'1. 2³ = 8 molécules\n2. 7 nouvelles molécules × 2400 = 16 800 nucléotides',notions:['Calcul réplication']},
      {id:'P1-12',difficulte:2,titre:'Introns, exons, épissage',enonce:'1. Intron vs exon.\n2. Épissage.\n3. Un même gène peut-il produire différentes protéines ?',correction:'1. Intron : non codant (éliminé). Exon : codant (conservé)\n2. Élimination introns + jonction exons → ARNm mature\n3. Oui : épissage alternatif → plusieurs protéines depuis 1 gène',notions:['Épissage']},
      {id:'P1-13',difficulte:3,titre:'Drépanocytose',enonce:'Mutation GAG→GTG dans le gène de la β-globine.\n1. Type de mutation.\n2. Quel AA remplacé.\n3. Conséquences sur l\'hémoglobine.',correction:'1. Substitution ponctuelle (A→T)\n2. Glu (acide glutamique) → Val (valine)\n3. Val hydrophobe → HbS se polymérise → GR en faucille → occlusions capillaires',notions:['Drépanocytose']},
      {id:'P1-14',difficulte:2,titre:'Les 3 types d\'ARN',enonce:'1. Citer les 3 ARN impliqués dans la traduction.\n2. Rôle de chacun.\n3. Définir anticodon.',correction:'1. ARNm · ARNt · ARNr\n2. ARNm : information. ARNt : transport des AA. ARNr : structure des ribosomes\n3. Triplet sur l\'ARNt complémentaire du codon ARNm (ex: AUG → UAC)',notions:['ARN']},
      {id:'P1-15',difficulte:3,titre:'Mucoviscidose et génétique',enonce:'Délétion de 3 nucléotides → perte de Phe508 dans CFTR.\n1. Type de mutation.\n2. Conséquence sur la protéine.\n3. Hérédité.',correction:'1. Délétion de 3 nt → pas de décalage (multiple de 3) → perte d\'1 AA\n2. CFTR perd la Phe508 → mal repliée → dégradée → canal Cl⁻ non fonctionnel\n3. Autosomique récessive (2 copies mutées nécessaires)',notions:['Mucoviscidose']},
      {id:'P1-16',difficulte:2,titre:'Expression différentielle des gènes',enonce:'1. Tous les gènes exprimés dans toutes les cellules ?\n2. Épigénétique.\n3. Exemple de régulation.',correction:'1. Non → expression différentielle selon le type cellulaire\n2. Modifications expression génique SANS modifier la séquence ADN (méthylation, histones)\n3. Abeille : ouvrière vs reine → même génome → gelée royale modifie méthylation',notions:['Expression génique']},
      {id:'P1-17',difficulte:3,titre:'Calcul composition ARNm',enonce:'Gène (brin non codant 5\'→3\') : 20% A · 30% T · 25% G · 25% C\nCalculer la composition de l\'ARNm.',correction:'ARNm = même composition que brin non codant mais T→U\n%A=20% · %U=30% · %G=25% · %C=25%',notions:['Calcul ARNm']},
      {id:'P1-18',difficulte:2,titre:'Ribosome et traduction',enonce:'1. Composition d\'un ribosome.\n2. Les 3 sites.\n3. Initiation-élongation-terminaison.',correction:'1. 2 sous-unités (ARNr + protéines)\n2. A (aminoacyl) · P (peptidyl) · E (exit)\n3. Init : AUG. Élong : codon par codon. Term : codon stop → dissociation',notions:['Ribosome']},
      {id:'P1-19',difficulte:3,titre:'Cancer et mutations',enonce:'1. Proto-oncogène.\n2. Oncogène vs suppresseur de tumeur.\n3. Pourquoi plusieurs mutations nécessaires.',correction:'1. Gène normal contrôlant la division (peut devenir oncogène si muté)\n2. Oncogène : activation permanente (dominant). Suppresseur : perte du frein (récessif, TP53)\n3. 5-10 mutations nécessaires → sécurité du génome → réduit risque spontané',notions:['Cancer']},
      {id:'P1-20',difficulte:3,titre:'Bilan ADN-protéine',enonce:'Gène de 900 nucléotides.\n1. Combien d\'AA dans la protéine.\n2. Combien de codons codants.\n3. Taille minimale de l\'ARNm.',correction:'1. 900/3 = 300 codons → ~298 AA (moins AUG initial et stop)\n2. 299 codons codants (dont AUG)\n3. > 900 nt (5\'UTR + 3\'UTR + coiffe + polyA)',notions:['Bilan']},
    ]
  },
  {
    id:'tectonique-premiere-svt', numero:2,
    titre:'Dynamique interne de la Terre',
    sousTitre:'Structure globe · Tectonique des plaques · Séismes · Volcanisme',
    icon:'🌋', color:'#f97316',
    notions:['Structure globe','Tectonique plaques','Séismes','Volcanisme'],
    exercices:[
      {id:'P2-01',difficulte:1,titre:'Structure interne de la Terre',enonce:'1. 4 grandes enveloppes terrestres.\n2. Laquelle est liquide.\n3. Lithosphère vs asthénosphère.',correction:'1. Croûte → Manteau → Noyau externe → Noyau interne\n2. Noyau externe (fer+nickel fondu) → champ magnétique\n3. Lithosphère : rigide (croûte + manteau sup.). Asthénosphère : ductile → déplacement des plaques',notions:['Structure globe']},
      {id:'P2-02',difficulte:1,titre:'Ondes sismiques',enonce:'1. Différence ondes P et S.\n2. Pourquoi S ne traversent pas le noyau externe.\n3. Comment cela a permis de découvrir la structure interne.',correction:'1. P (compression) : solides + liquides. S (cisaillement) : solides uniquement\n2. Noyau externe = liquide → S absorbées → zone d\'ombre\n3. Zone d\'ombre détectée → noyau externe liquide (Oldham, 1906)',notions:['Ondes sismiques']},
      {id:'P2-03',difficulte:1,titre:'Types de frontières de plaques',enonce:'Décrire les 3 types de frontières et phénomènes associés.',correction:'1. Divergence : dorsales + volcanisme effusif + séismes superficiels\n2. Subduction : fosses + volcanisme explosif + séismes profonds\n3. Collision : montagnes + séismes intenses\n4. Transformantes : coulissement → séismes (San Andreas)',notions:['Frontières plaques']},
      {id:'P2-04',difficulte:1,titre:'Convection mantellique',enonce:'1. Définir.\n2. Pourquoi le manteau peut "couler".\n3. Rôle dans le déplacement des plaques.',correction:'1. Mouvement circulaire de la roche mantellique (chaude monte, froide descend)\n2. Solide mais ductile (viscosité très élevée) → coule sur Ma sans fondre\n3. Plaques "portées" par les cellules de convection → déplacement cm/an',notions:['Convection']},
      {id:'P2-05',difficulte:2,titre:'Preuves du déplacement des plaques',enonce:'4 preuves expliquées.',correction:'1. Anomalies magnétiques symétriques des dorsales\n2. Alignement volcans de point chaud (Hawaï)\n3. Fossiles identiques sur continents séparés (Glossopteris)\n4. Ophiolites (roches océaniques dans les montagnes)',notions:['Preuves tectonique']},
      {id:'P2-06',difficulte:2,titre:'Subduction — mécanisme',enonce:'1. Pourquoi la plaque océanique plonge.\n2. Que se passe-t-il quand elle subducte.\n3. Formation du magma.',correction:'1. Plus dense (~3,0) que continentale (~2,7) → plonge par gravité\n2. Descend → chauffe → dégazage eau → hydratation du manteau sus-jacent\n3. Eau abaisse point de fusion → fusion partielle → magma → volcans explosifs',notions:['Subduction']},
      {id:'P2-07',difficulte:2,titre:'Formation des Andes',enonce:'Nazca subducte sous Amérique du Sud.\n1. Type de subduction.\n2. Pourquoi les Andes sont volcaniques.\n3. Séismes profonds.',correction:'1. Océanique sous continentale\n2. Eau de la plaque → fusion partielle manteau → magma → stratovolcans\n3. Plaque Nazca descend encore → séismes jusqu\'à 700 km (zone Wadati-Benioff)',notions:['Andes']},
      {id:'P2-08',difficulte:2,titre:'Himalaya — collision continentale',enonce:'1. Pourquoi pas de subduction.\n2. Vitesse plaque indienne.\n3. Pourquoi l\'Everest grandit encore.',correction:'1. 2 plaques continentales légères → ni l\'une ne subducte → compression\n2. ~5 cm/an vers le nord (depuis ~50 Ma)\n3. Compression toujours active → soulèvement quelques mm/an',notions:['Himalaya']},
      {id:'P2-09',difficulte:2,titre:'Séismes — mécanisme et mesure',enonce:'1. Foyer et épicentre.\n2. Magnitude vs intensité.\n3. Profondeur max des séismes de subduction.',correction:'1. Foyer : point de rupture. Épicentre : projection à la surface\n2. Magnitude : énergie libérée (Richter). Intensité : effets en surface (MSK)\n3. Jusqu\'à 700 km (zone Wadati-Benioff)',notions:['Séismes']},
      {id:'P2-10',difficulte:2,titre:'Volcanisme — types',enonce:'Comparer volcans effusifs (point chaud/dorsale) et explosifs (subduction).',correction:'EFFUSIFS : basalte fluide · coulées calmes. Ex: Kilauea\nEXPLOSIFS : andésite/rhyolite visqueuse · éruptions violentes · nuées ardentes. Ex: Pinatubo',notions:['Volcanisme']},
      {id:'P2-11',difficulte:2,titre:'La Pangée',enonce:'1. Qu\'est-ce que la Pangée ? Quand.\n2. Qui a proposé la dérive des continents.\n3. Preuves.',correction:'1. Supercontinent unique (~300 Ma), fragmenté depuis ~180 Ma\n2. Alfred Wegener (1912)\n3. Similitudes côtes · fossiles identiques · géologie · traces glaciation',notions:['Pangée']},
      {id:'P2-12',difficulte:3,titre:'Tsunamis',enonce:'1. Comment un séisme génère un tsunami.\n2. Pourquoi peu détectable en plein océan.\n3. Exemple meurtrier.',correction:'1. Séisme → déplacement vertical fond → déplace colonne eau → onde\n2. Amplitude <1m · longueur d\'onde >100 km → imperceptible. Côte : fond peu profond → montée\n3. Sumatra (2004) : 9,1 Mw → 230 000 morts',notions:['Tsunamis']},
      {id:'P2-13',difficulte:2,titre:'Risques géologiques et prévention',enonce:'1. Peut-on prévoir les séismes.\n2. Comment prévoir les éruptions.\n3. 3 mesures de réduction du risque sismique.',correction:'1. Non : impossible (probabiliste seulement)\n2. Surveillance sismicité + déformation sol + émissions gaz (SO₂)\n3. Construction parasismique · plans ORSEC · information + exercices',notions:['Risques']},
      {id:'P2-14',difficulte:3,titre:'Dorsale médio-atlantique',enonce:'1. Formation de la croûte océanique.\n2. Pourquoi croûte océanique toujours < 200 Ma.\n3. Anomalies magnétiques symétriques.',correction:'1. Remontée manteau → décompression → basalte → nouvelle croûte\n2. Créée aux dorsales ET détruite aux subductions → équilibre dynamique\n3. Aimantation du basalte enregistre inversions → bandes symétriques → preuve expansion (Vine & Matthews 1963)',notions:['Dorsale']},
      {id:'P2-15',difficulte:2,titre:'Ceinture de feu du Pacifique',enonce:'1. Où se concentrent séismes et volcans.\n2. Définir "ceinture de feu".\n3. Pourquoi l\'Islande est si volcanique.',correction:'1. Aux frontières de plaques\n2. Zone volcanique + sismique entourant le Pacifique → 90% séismes + 75% volcans\n3. Sur la dorsale mid-atlantique ET un point chaud → double source',notions:['Ceinture de feu']},
      {id:'P2-16',difficulte:3,titre:'Ophiolites et paléo-océans',enonce:'Ophiolites dans les Alpes.\n1. Définir ophiolite.\n2. Histoire géologique reconstituée.\n3. Apport sur la formation des Alpes.',correction:'1. Séquence roches océaniques (basaltes en coussin + gabbros + péridotites) dans une montagne\n2. Paléo-océan Téthys → subduction → collision → lambeaux coinés\n3. Alpes = collision adriatique-Europe après fermeture Téthys',notions:['Ophiolites']},
      {id:'P2-17',difficulte:2,titre:'Déformation des roches',enonce:'1. Définir pli et faille.\n2. Contexte géologique de formation.\n3. Faille normale vs inverse.',correction:'1. Pli : déformation ductile. Faille : rupture cassante avec déplacement\n2. Plis : compression. Failles : extension, compression ou cisaillement\n3. Normale : compartiment sup. descend (extension). Inverse : monte (compression)',notions:['Déformation']},
      {id:'P2-18',difficulte:3,titre:'Arc volcanique du Japon',enonce:'1. Définir arc volcanique.\n2. Formation des volcans japonais.\n3. Pourquoi si dangereux.',correction:'1. Volcans alignés parallèlement à une fosse de subduction\n2. Plaques Pacifique + Philippin subductent → eau libérée → fusion manteau → volcans\n3. Éruptions explosives (silice élevée) · nuées ardentes · tsunamis + forte densité de population',notions:['Arc volcanique']},
      {id:'P2-19',difficulte:2,titre:'Paléomagnétisme',enonce:'1. Définir paléomagnétisme.\n2. Comment les roches "enregistrent" le champ magnétique.\n3. Comment cela prouve la dérive des continents.',correction:'1. Étude de l\'aimantation des roches anciennes → reconstitue le champ magnétique passé\n2. Minéraux ferromagnétiques s\'orientent pendant le refroidissement → "fossilise" la direction\n3. Roches d\'un même âge sur différents continents → directions différentes → continents ont bougé',notions:['Paléomagnétisme']},
      {id:'P2-20',difficulte:3,titre:'Bilan tectonique et ressources naturelles',enonce:'Comment la tectonique explique la répartition des ressources.\n1. Pétrole et gaz.\n2. Minéraux sulfurés.\n3. Diamants.',correction:'1. Pétrole : bassins sédimentaires formés par la tectonique (rifts + marges passives)\n2. Sulfures Cu, Zn : fumeurs noirs des dorsales (hydrothermalisme)\n3. Diamants : manteau profond (P et T élevées) → remontés par kimberlites',notions:['Ressources naturelles']},
    ]
  },
  {
    id:'ecosystemes-premiere-svt', numero:3,
    titre:'Écosystèmes & Services environnementaux',
    sousTitre:'Réseaux trophiques · Flux énergie · Biodiversité · Services écosystémiques',
    icon:'🌿', color:'#22c55e',
    notions:['Réseau trophique','Flux énergie','Services écosystémiques'],
    exercices:[
      {id:'P3-01',difficulte:1,titre:'Niveaux trophiques',enonce:'1. Définir les 4 niveaux trophiques.\n2. Rôle des décomposeurs.\n3. Pourquoi < 5 niveaux dans une chaîne.',correction:'1. Producteurs primaires → Cons. primaires (herbivores) → Cons. secondaires → Cons. tertiaires\n2. Dégradent matière morte → recyclent minéraux → permettent aux producteurs de se nourrir\n3. Règle des 10% → après 5 niveaux, énergie insuffisante',notions:['Niveaux trophiques']},
      {id:'P3-02',difficulte:1,titre:'Règle des 10%',enonce:'Prairie : 10 000 kg végétaux.\n1. Biomasse herbivores.\n2. Carnivores.\n3. Super-prédateurs.',correction:'1. 1 000 kg\n2. 100 kg\n3. 10 kg\n→ Grand carnivore a besoin 1000× son poids en végétaux',notions:['Règle 10%']},
      {id:'P3-03',difficulte:1,titre:'Services écosystémiques',enonce:'1. Définir.\n2. Les 4 catégories.\n3. Exemple de valeur économique.',correction:'1. Bénéfices gratuits des écosystèmes pour les humains\n2. Approvisionnement · Régulation · Soutien · Culturels\n3. Pollinisation = 2,3 Md€/an France',notions:['Services éco.']},
      {id:'P3-04',difficulte:1,titre:'Richesse spécifique et Shannon',enonce:'1. Définir richesse spécifique (S).\n2. Définir indice de Shannon (H).\n3. Avantage de Shannon vs S.',correction:'1. Nombre d\'espèces différentes dans un milieu\n2. H = -Σ pᵢ × log₂(pᵢ) → mesure diversité + équitabilité\n3. Shannon tient compte de l\'abondance relative (pas seulement le nombre)',notions:['Indicateurs']},
      {id:'P3-05',difficulte:2,titre:'Calcul d\'indice de Shannon',enonce:'Bois : Chêne 50 · Hêtre 30 · Charme 20 ind.\nCalculer H.',correction:'p = 0,50 / 0,30 / 0,20\nH = -[0,50×(-1) + 0,30×(-1,737) + 0,20×(-2,322)]\nH ≈ 1,49 bits',notions:['Calcul Shannon']},
      {id:'P3-06',difficulte:2,titre:'Réseau trophique — cascade',enonce:'Étang : algues→zooplancton→poissons herbivores→brochet→héron.\n1. Chaîne principale.\n2. Si poissons herbivores disparaissent.\n3. Nom de ce phénomène.',correction:'1. Algues→Zooplancton→Poissons→Brochet→Héron\n2. Algues prolifèrent · brochet diminue · héron diminue\n3. Cascade trophique',notions:['Réseau trophique']},
      {id:'P3-07',difficulte:2,titre:'Le loup à Yellowstone',enonce:'Réintroduction du loup (1995).\n1. Effets sur les cerfs.\n2. Sur la végétation.\n3. Sur les rivières.',correction:'1. Cerfs chassés des vallées → comportement alimentaire change\n2. Végétation riveraine se régénère\n3. Rives stabilisées → méandres reformés → castor revient → biodiversité aquatique',notions:['Espèce clé de voûte']},
      {id:'P3-08',difficulte:2,titre:'Fragmentation des habitats',enonce:'1. Définir fragmentation.\n2. Conséquences génétiques.\n3. Corridor écologique.',correction:'1. Division habitat continu en fragments isolés\n2. Isolement → dérive génétique → consanguinité → perte diversité\n3. Couloir végétal reliant fragments → flux génique (Trame Verte et Bleue)',notions:['Fragmentation']},
      {id:'P3-09',difficulte:2,titre:'Biomes et zonation altitudinale',enonce:'1. Définir biome.\n2. 4 biomes terrestres.\n3. Zonation altitudinale.',correction:'1. Grande unité écologique (climat + végétation dominante)\n2. Forêt tropicale · Toundra · Savane · Forêt tempérée · Désert\n3. Bandes selon altitude (≈latitude) : forêt → prairie alpine → rocailles → neige',notions:['Biome']},
      {id:'P3-10',difficulte:2,titre:'Déclin des pollinisateurs',enonce:'1. Pollinisation.\n2. Pourquoi les abeilles déclinent.\n3. Impact sur l\'agriculture.',correction:'1. Transport pollen → fécondation → fruits et graines\n2. Néonicotinoïdes · Varroa · perte d\'habitats · changement climatique\n3. 75% espèces cultivées concernées. Valeur = 235-577 Md€/an',notions:['Pollinisation']},
      {id:'P3-11',difficulte:2,titre:'Productivité des écosystèmes',enonce:'1. Comment mesurer PPB et PPN.\n2. Relation PPB, respiration, PPN.\n3. Quel écosystème le plus productif.',correction:'1. PPB : fixation totale CO₂. PPN : CO₂ absorbé à la lumière\n2. PPN = PPB - Respiration\n3. Forêts tropicales + estuaires : ~2000 g C/m²/an',notions:['Productivité']},
      {id:'P3-12',difficulte:3,titre:'Cycle de l\'azote',enonce:'1. Pourquoi N₂ inaccessible aux plantes.\n2. Comment devient-il assimilable.\n3. Dénitrification.',correction:'1. N₂ = très stable (triple liaison) → plantes ne peuvent pas fixer\n2. FBN : Rhizobium → NH₃. Nitrification : NH₃ → NO₃⁻\n3. Bactéries anaérobies : NO₃⁻ → N₂ → retour atmosphère',notions:['Cycle azote']},
      {id:'P3-13',difficulte:2,titre:'6ème extinction de masse',enonce:'1. Taux extinction actuel vs naturel.\n2. Causes principales.\n3. Peut-on inverser la tendance.',correction:'1. 100-1000× supérieur au taux naturel\n2. HIPPS : Habitat · Invasives · Pollution · Prélèvements · Spéciation perturbée + Climat\n3. Oui partiellement (condor, lynx ibérique) mais changements systémiques nécessaires',notions:['6ème extinction']},
      {id:'P3-14',difficulte:3,titre:'Aires protégées et conservation',enonce:'1. Définir aire protégée.\n2. Objectif 30×30.\n3. Limites des AP.',correction:'1. Zone dont la gestion conserve biodiversité + services\n2. 30% terres et mers protégées d\'ici 2030 (CDB, COP15 Montréal 2022)\n3. Paper parks · conflits locaux · trop petites · espèces migrent avec le changement climatique',notions:['Aires protégées']},
      {id:'P3-15',difficulte:2,titre:'Invasions biologiques',enonce:'1. Définir espèce invasive.\n2. Comment devient-elle invasive.\n3. Exemple en France + impact.',correction:'1. Espèce introduite qui prolifère et perturbe les écosystèmes locaux\n2. Absence de prédateurs + ressources abondantes + haute fécondité\n3. Frelon asiatique : dévore abeilles → déclin ruches + perturbation pollinisation',notions:['Espèces invasives']},
      {id:'P3-16',difficulte:2,titre:'Paiements pour services écosystémiques',enonce:'1. Définir PSE.\n2. Exemple concret.\n3. Limites.',correction:'1. Mécanisme économique : bénéficiaires paient les producteurs de services\n2. New York City : paye agriculteurs du bassin versant → eau de qualité\n3. Difficile de valoriser tout · risque de marchandisation · exclusion des communautés',notions:['PSE']},
      {id:'P3-17',difficulte:3,titre:'Changement climatique et écosystèmes',enonce:'1. Effets sur la phénologie.\n2. Déplacement des aires de répartition.\n3. Blanchissement des coraux.',correction:'1. Floraison + précoce · migration oiseaux décalée · désynchronisation prédateurs/proies\n2. ~6 km/décennie vers les pôles · 6 m/décennie en altitude\n3. T° eau > +1°C → coraux expulsent zooxanthelles → blanchissement → mort si prolongé',notions:['Changement climatique']},
      {id:'P3-18',difficulte:2,titre:'Upwelling et productivité marine',enonce:'1. Pourquoi les zones d\'upwelling sont très productives.\n2. Thermocline.\n3. Phytoplancton et cycle du carbone.',correction:'1. Remontée d\'eaux profondes → nutriments NO₃⁻, PO₄³⁻ → explosion phytoplancton\n2. Couche de forte variation de T° → stratification → empêche échanges verticaux\n3. 50% photosynthèse mondiale. Pompe biologique → séquestration carbone océan',notions:['Productivité marine']},
      {id:'P3-19',difficulte:3,titre:'Restauration écologique',enonce:'1. Définir restauration écologique.\n2. Différence avec conservation.\n3. Exemple réussi.',correction:'1. Processus actif pour restaurer intégrité d\'un écosystème dégradé\n2. Conservation : protéger ce qui reste. Restauration : recréer ce qui est perdu\n3. Réintroduction du loup à Yellowstone (1995) → cascade écologique positive',notions:['Restauration']},
      {id:'P3-20',difficulte:3,titre:'Bilan écosystèmes et bien-être humain',enonce:'Décrire les liens entre santé des écosystèmes et bien-être humain (3 exemples).',correction:'1. SANTÉ : forêts tropicales = réservoir → 60% médicaments. Perturbées → zoonoses\n2. ALIMENTATION : 95% nourriture produite grâce aux sols vivants. Dégradation → menace\n3. EAU + CLIMAT : forêts régulent cycle eau + stockent 250 Gt C. Déforestation → sécheresses + CO₂',notions:['One Health']},
    ]
  },
  {
    id:'ecosystemes-humains-premiere-svt', numero:4,
    titre:'Écosystèmes & Activité humaine',
    sousTitre:'IPBES · Pressions anthropiques · Conservation · Trame Verte · Aires protégées',
    icon:'🏭', color:'#f59e0b',
    notions:['IPBES','Pressions anthropiques','Conservation'],
    exercices:[
      {id:'P4-01',difficulte:1,titre:'Les 5 pressions IPBES',enonce:'Citer et ordonner les 5 pressions sur la biodiversité.',correction:'1. Changement utilisation terres (1ère cause)\n2. Surexploitation\n3. Changement climatique\n4. Pollution\n5. Espèces invasives',notions:['IPBES']},
      {id:'P4-02',difficulte:1,titre:'Déforestation',enonce:'1. Causes de la déforestation tropicale.\n2. Surface détruite/an.\n3. Conséquences sur le CO₂.',correction:'1. Élevage bovin · palmier à huile · soja · bois\n2. ~10-15 millions ha/an\n3. Libère ~4,8 Gt CO₂/an + détruit puits de carbone',notions:['Déforestation']},
      {id:'P4-03',difficulte:2,titre:'Surpêche mondiale',enonce:'1. Définir surpêche.\n2. % stocks surexploités.\n3. Solutions pêche durable.',correction:'1. Prélèvement > capacité de renouvellement → effondrement\n2. ~35% surexploités (FAO 2022)\n3. Quotas basés sur la science · AMP · certifications MSC · réduire subventions',notions:['Surpêche']},
      {id:'P4-04',difficulte:2,titre:'Pollution lumineuse',enonce:'1. Définir.\n2. Effets sur la faune nocturne.\n3. Solutions.',correction:'1. Émission excessive lumière artificielle la nuit\n2. Oiseaux désorientation · insectes épuisement · tortues marines désorientation\n3. Détection de mouvement · filtres orange · réduire intensité',notions:['Pollution lumineuse']},
      {id:'P4-05',difficulte:2,titre:'Commerce illégal d\'espèces',enonce:'1. Définir CITES.\n2. Espèces victimes.\n3. Impact sur les populations.',correction:'1. Convention sur le commerce international d\'espèces menacées (1975, 183 pays)\n2. Éléphant · rhinocéros · tigre · pangolin (+ braconné au monde)\n3. Pangolin : 1 million/an → certaines espèces menacées d\'extinction',notions:['CITES']},
      {id:'P4-06',difficulte:2,titre:'Trame Verte et Bleue',enonce:'1. Définir TVB.\n2. Pourquoi nécessaire.\n3. Mise en œuvre en France.',correction:'1. Réseau écologique national reliant espaces naturels (continuités écologiques)\n2. Fragmentation → isolement génétique → extinction. TVB permet dispersion + flux génique\n3. SRCE → intégrés dans PLU → corridors, haies, passages à faune sous routes',notions:['TVB']},
      {id:'P4-07',difficulte:2,titre:'Capital naturel',enonce:'1. Définir capital naturel.\n2. Pourquoi valoriser économiquement la biodiversité.\n3. Limites de cette approche.',correction:'1. Stock de ressources + services fournis par les écosystèmes\n2. Rendre "visible" ce qui est traité comme gratuit → intégrer dans les décisions économiques\n3. Valeurs non marchandes difficiles à quantifier · risque de marchandisation',notions:['Capital naturel']},
      {id:'P4-08',difficulte:2,titre:'Conservation ex situ',enonce:'1. Définir.\n2. Méthodes.\n3. Exemple remarquable.',correction:'1. Conservation en dehors du milieu naturel\n2. Banques de graines · cryoconservation · élevage en captivité · jardins botaniques\n3. Svalbard Global Seed Vault : 1,3 million d\'échantillons de semences en Arctique',notions:['Conservation ex situ']},
      {id:'P4-09',difficulte:3,titre:'Biodiversité urbaine',enonce:'1. Les villes peuvent-elles abriter de la biodiversité ?\n2. Végétalisation urbaine.\n3. Exemple de ville exemplaire.',correction:'1. Oui : parfois > zones agricoles intensives (jardins + friches + parcs)\n2. Toitures végétalisées · jardins partagés · désimperméabilisation · gestion différenciée\n3. Berlin (10% territoire naturel) · Singapore (toitures vertes obligatoires)',notions:['Biodiversité urbaine']},
      {id:'P4-10',difficulte:2,titre:'Effet de lisière',enonce:'1. Définir.\n2. Conséquences biodiversité fragment forestier.\n3. Comment minimiser lors d\'une AP.',correction:'1. Zone de transition entre 2 habitats → conditions intermédiaires\n2. Espèces forestières perdent habitat · prédation des nids augmente · dessèchement\n3. AP grande taille (forme ronde) · minimiser longueur de lisière · protéger le cœur',notions:['Effet de lisière']},
      {id:'P4-11',difficulte:2,titre:'Pollution océans par plastiques',enonce:'1. Comment les plastiques atteignent les océans.\n2. Le continente de déchets du Pacifique.\n3. Impact sur la faune marine.',correction:'1. Fleuves · déversements directs · filets abandonnés · microplastiques (cosmétiques)\n2. GPGPN : accumulation débris → enrichissement microplastiques (~80 000 tonnes)\n3. Ingestion (tortues) · étouffement (filets fantômes) · bioaccumulation dans chaîne alimentaire',notions:['Plastiques océans']},
      {id:'P4-12',difficulte:3,titre:'Solutions fondées sur la Nature',enonce:'1. Définir SFN.\n2. Exemples concrets.\n3. Avantage vs solutions "grises".',correction:'1. Solutions s\'appuyant sur les processus naturels pour répondre aux défis sociétaux\n2. Restauration mangroves (protection côtière) · zones humides péri-urbaines · agroforesterie\n3. Moins coûteuses · co-bénéfices biodiversité · résilientes · peu de maintenance',notions:['SFN']},
      {id:'P4-13',difficulte:2,titre:'Migration des espèces et changement climatique',enonce:'1. Comment le réchauffement contraint les espèces à se déplacer.\n2. Vitesse de déplacement nécessaire.\n3. Espèces qui ne peuvent pas s\'adapter.',correction:'1. Niche climatique se déplace → espèces doivent suivre ou s\'adapter\n2. ~17 km/décennie vers les pôles · ~11 m/décennie en altitude\n3. Endémiques d\'îles ou de sommets · dispersion lente · spécialistes stricts',notions:['Migration climatique']},
      {id:'P4-14',difficulte:3,titre:'Économie de la conservation',enonce:'1. Coût conservation vs inaction.\n2. Rentabilité des AP.\n3. Qui finance la conservation.',correction:'1. Conservation : ~20-30 Md$/an. Inaction : 10-20× supérieure en pertes de services\n2. 1$ → 100$ bénéfices (tourisme + pêche + eau + carbone)\n3. Gouvernements (50%) · banques de développement · secteur privé · marchés carbone',notions:['Financement conservation']},
      {id:'P4-15',difficulte:2,titre:'Agriculture et biodiversité',enonce:'1. Pourquoi agriculture intensive réduit biodiversité.\n2. Agroécologie.\n3. Comment agriculture peut héberger de la biodiversité.',correction:'1. Monocultures · pesticides · drainage zones humides · suppression haies\n2. Principes écologiques à l\'agriculture → services écosystémiques + moins d\'intrants\n3. Haies · jachères fleuries · cultures associées · prairies permanentes · agroforesterie',notions:['Agriculture et biodiversité']},
      {id:'P4-16',difficulte:2,titre:'Compensation écologique',enonce:'1. Définir.\n2. Principe ERC (Éviter-Réduire-Compenser).\n3. Limites.',correction:'1. Mesures compensant les atteintes à la biodiversité d\'un aménagement\n2. D\'abord éviter · puis réduire · enfin compenser les impacts résiduels\n3. Difficile de créer habitat équivalent · non-équivalence · décalage temporel',notions:['Compensation']},
      {id:'P4-17',difficulte:3,titre:'Convention sur la Diversité Biologique',enonce:'1. Définir CDB. Quand signée.\n2. Les 3 objectifs.\n3. Objectifs de Kunming-Montréal (COP15).',correction:'1. Traité international sur la conservation biodiversité (Rio, 1992, 196 parties)\n2. Conservation · utilisation durable · partage équitable des bénéfices\n3. 30×30 · restauration 30% écosystèmes dégradés · réduction pesticides 50% · 200 Md$/an',notions:['CDB']},
      {id:'P4-18',difficulte:2,titre:'Productivité marine et lumière',enonce:'1. Rôle lumière dans les écosystèmes marins.\n2. Zone euphotique.\n3. Pourquoi mangroves et récifs si productifs.',correction:'1. Énergie motrice photosynthèse phytoplancton → base chaînes alimentaires marines\n2. 0-200 m où pénètre assez de lumière → productivité élevée\n3. Mangroves : littoral peu profond + nutriments + abris. Récifs : zooxanthelles + structure 3D',notions:['Productivité marine']},
      {id:'P4-19',difficulte:3,titre:'Renforcement des populations',enonce:'1. Quand utilise-t-on cette technique.\n2. Exemple de succès.\n3. Risques génétiques.',correction:'1. Population trop petite → libération d\'individus élevés en captivité\n2. Condor de Californie : 27 ind. (1987) → 500+ aujourd\'hui\n3. Individus adaptés à la captivité · dépression de croisement · consanguinité',notions:['Renforcement population']},
      {id:'P4-20',difficulte:3,titre:'Bilan biodiversité et activité humaine',enonce:'La biodiversité est-elle compatible avec le développement humain ? 3 arguments.',correction:'1. NON si modèle actuel continue : économie linéaire · limites planétaires dépassées\n2. OUI si transition : économie régénérative · solutions basées sur la nature → emplois + protection\n3. EXEMPLES : Costa Rica (90% ENR + forêts + tourisme). Rwanda (gorilles → 1er revenu touristique)',notions:['Bilan']},
    ]
  },
  {
    id:'ressources-naturelles-premiere-svt', numero:5,
    titre:'Ressources naturelles & Développement durable',
    sousTitre:'Eau · Sols · Énergie · Empreinte écologique · Transition',
    icon:'💧', color:'#0891b2',
    notions:['Eau','Sols','Énergie','Empreinte écologique','Transition'],
    exercices:[
      {id:'P5-01',difficulte:1,titre:'Cycle de l\'eau et ressources',enonce:'1. Étapes du cycle de l\'eau.\n2. % eau douce accessible.\n3. Impact de l\'agriculture.',correction:'1. Évaporation+Transpiration → Condensation → Précipitations → Ruissellement → Nappes\n2. Eau douce : 2,5% totale. Accessible : < 1%\n3. Agriculture = 70% prélèvements. Irrigation → abaissement nappes · salinisation',notions:['Cycle eau']},
      {id:'P5-02',difficulte:1,titre:'Bilan hydrique agricole',enonce:'Blé : 450 mm eau/saison. Précipitations : 300 mm.\n1. Déficit.\n2. Volume à apporter par hectare.\n3. Irrigation recommandée.',correction:'1. Déficit = 150 mm\n2. 0,150 m × 10 000 m² = 1 500 m³/ha\n3. Goutte-à-goutte (90-95% efficacité)',notions:['Bilan hydrique']},
      {id:'P5-03',difficulte:2,titre:'Salinisation des sols',enonce:'1. Comment la salinisation se produit.\n2. Conséquences agricoles.\n3. Régions touchées.',correction:'1. Irrigation excessive → eau s\'évapore → sels s\'accumulent en surface\n2. Osmose inverse → plantes ne peuvent plus absorber eau → mort des cultures\n3. Mer d\'Aral · Mésopotamie · Pakistan · Espagne (Murcie)',notions:['Salinisation']},
      {id:'P5-04',difficulte:2,titre:'Empreinte écologique',enonce:'1. Définir.\n2. Jour du Dépassement.\n3. France vs pays en développement.',correction:'1. Surface nécessaire pour produire les ressources consommées + absorber les déchets\n2. Jour où l\'humanité a consommé toutes les ressources régénérables annuelles (2024 : 1er août)\n3. France : 4,7 planètes. Bangladesh : 0,9 planète. USA : 5,0 planètes',notions:['Empreinte écologique']},
      {id:'P5-05',difficulte:2,titre:'Énergie fossile',enonce:'1. Définir.\n2. Réserves estimées.\n3. Comparaison CO₂ : charbon vs gaz vs pétrole.',correction:'1. Énergie stockée dans dépôts géologiques de matière organique fossilisée\n2. Charbon ~130 ans · Pétrole ~50 ans · Gaz ~50 ans\n3. CO₂/kWh : Charbon 800-1000 g · Pétrole 650 g · Gaz 400 g',notions:['Énergies fossiles']},
      {id:'P5-06',difficulte:2,titre:'Énergies renouvelables — comparaison',enonce:'Comparer 4 ENR : avantages et inconvénients.',correction:'Solaire : inépuisable · pas entretien. Mais : intermittent · matériaux rares\nÉolien : peu d\'espace. Mais : bruit · oiseaux · intermittent\nHydraulique : régulable · stockage. Mais : habitat fluvial · peu de sites\nBiomasse : stockable. Mais : surfaces agricoles · particules',notions:['ENR']},
      {id:'P5-07',difficulte:2,titre:'Calcul empreinte carbone des transports',enonce:'Voiture 8000 km (0,15) · train 2000 km (0,005) · avion 4000 km (0,25) kgCO₂/km.\nCalculer le total.',correction:'Voiture : 1,20 t CO₂\nTrain : 0,01 t CO₂\nAvion : 1,00 t CO₂\nTotal : 2,21 t CO₂/an\n→ Avion disproportionné : 1000 km avion ≈ 8000 km voiture',notions:['Bilan carbone']},
      {id:'P5-08',difficulte:3,titre:'Mix énergétique et transition',enonce:'1. Définir mix énergétique.\n2. Comment la France atteint neutralité carbone 2050.\n3. Rôle du nucléaire.',correction:'1. Ensemble des sources d\'énergie utilisées (proportions)\n2. Électrifier les usages + ENR (50%) + nucléaire + efficacité + séquestration\n3. Très faibles émissions (~6 gCO₂eq/kWh) · pilotable · mais déchets radioactifs',notions:['Mix énergétique']},
      {id:'P5-09',difficulte:2,titre:'Sols et matière organique',enonce:'1. Pourquoi la MO du sol est essentielle.\n2. Comment l\'agriculture intensive la fait diminuer.\n3. Pratiques pour l\'augmenter.',correction:'1. Structure · rétention eau · CEC · biodiversité du sol · stockage C\n2. Labour profond (oxydation) · monocultures · brûlis → perte 0,1-0,5%/an\n3. Semis direct · CIPAN · compost · agroforesterie · prairies permanentes',notions:['Matière organique sol']},
      {id:'P5-10',difficulte:2,titre:'Eau virtuelle',enonce:'1. Définir eau virtuelle.\n2. Litres pour 1 kg bœuf · poulet · blé.\n3. Implication pour notre alimentation.',correction:'1. Volume d\'eau pour produire un bien tout au long de sa chaîne\n2. Bœuf : 15 000 L. Poulet : 4 300 L. Blé : 1 300 L\n3. Alimentation = 70% de notre empreinte eau. Réduire viande rouge = levier majeur',notions:['Eau virtuelle']},
      {id:'P5-11',difficulte:3,titre:'Lithium et batteries',enonce:'1. Où se trouve le lithium.\n2. Impact environnemental extraction.\n3. Alternatives et recyclage.',correction:'1. "Triangle du lithium" (Chili, Argentine, Bolivie) = 60% des réserves\n2. Évaporation dans salars → consomme eau · pollue nappes · perturbe écosystèmes\n3. Batteries sodium-ion · recyclage (obligatoire UE 95% d\'ici 2030)',notions:['Matières critiques']},
      {id:'P5-12',difficulte:2,titre:'Objectifs de Développement Durable',enonce:'1. Qu\'est-ce que les ODD.\n2. 5 ODD liés aux ressources naturelles.\n3. Pourquoi interdépendants.',correction:'1. 17 objectifs ONU (Agenda 2030) pour développement durable (193 pays, 2015)\n2. ODD2 · ODD6 · ODD7 · ODD13 · ODD14 · ODD15\n3. ODD13 (climat) affecte ODD2 (alimentation). ODD8 (croissance) vs ODD12 (consommation)',notions:['ODD']},
      {id:'P5-13',difficulte:3,titre:'La géothermie',enonce:'1. Définir géothermie.\n2. Types (très basse, basse, haute énergie).\n3. Où la haute énergie est utilisée.',correction:'1. Exploitation de la chaleur interne de la Terre\n2. Très basse (<30°C) : pompes à chaleur. Basse (30-150°C) : chauffage urbain. Haute (>150°C) : électricité\n3. Islande (100% électricité géothermique) · Nouvelle-Zélande · Kenya · Italie',notions:['Géothermie']},
      {id:'P5-14',difficulte:2,titre:'Économie circulaire',enonce:'1. Linéaire vs circulaire.\n2. Les 7R.\n3. Exemple de symbiose industrielle.',correction:'1. Linéaire : extraire→produire→jeter. Circulaire : déchets = ressources d\'un autre\n2. Refuser · Réduire · Réutiliser · Réparer · Reconditionner · Recycler · Récupérer\n3. Kalundborg (Danemark) : raffinerie → vapeur → centrale → eaux → pisciculture...',notions:['Économie circulaire']},
      {id:'P5-15',difficulte:2,titre:'Forêts et stockage de carbone',enonce:'1. Quantité de C stockée.\n2. Forêt la plus importante.\n3. Que se passe-t-il si on la coupe.',correction:'1. ~800 Gt C (végétation + sols forestiers)\n2. Amazonie : 150-200 Gt C · 10% productivité primaire mondiale\n3. Libération CO₂ + moins de pluie recyclée → risque de savannisation',notions:['Forêts et carbone']},
      {id:'P5-16',difficulte:3,titre:'Pénurie d\'eau dans le monde',enonce:'1. Définir stress hydrique.\n2. Régions touchées en 2050.\n3. Solutions.',correction:'1. < 1 700 m³/personne/an. Pénurie : < 1 000\n2. Moyen-Orient · Inde · Chine du Nord · Méditerranée\n3. Goutte-à-goutte · recyclage eaux usées · dessalement · prix de l\'eau réel',notions:['Pénurie eau']},
      {id:'P5-17',difficulte:2,titre:'Phosphore — ressource critique',enonce:'1. Pourquoi essentiel.\n2. Réserves mondiales.\n3. "Pic phosphore".',correction:'1. ATP + acides nucléiques + membranes → indispensable aux plantes · non substituable\n2. 75% au Maroc (Sahara occidental)\n3. Moment de production maximale puis déclin → ressource non renouvelable → urgence recyclage',notions:['Phosphore']},
      {id:'P5-18',difficulte:3,titre:'Vers une alimentation durable',enonce:'1. Comment réduire de 50% l\'impact environnemental.\n2. Régime planétaire EAT-Lancet.\n3. Obstacles.',correction:'1. Réduire viande rouge (-50%) · doubler légumineuses · réduire gaspillage\n2. 2500 kcal/j : max 14g bœuf/j · beaucoup de légumineuses + légumes\n3. Habitudes culturelles · subsidiation élevage · prix · déserts alimentaires',notions:['Alimentation durable']},
      {id:'P5-19',difficulte:2,titre:'Déchets et gestion',enonce:'1. Hiérarchie des déchets (5R-UE).\n2. Taux de recyclage France vs objectifs.\n3. Gaspillage alimentaire.',correction:'1. Prévention → Réutilisation → Recyclage → Valorisation énergétique → Élimination\n2. France 2022 : 55% emballages (objectif 70% en 2030)\n3. 10 millions tonnes/an France → loi anti-gaspillage · applis · dates péremption',notions:['Gestion déchets']},
      {id:'P5-20',difficulte:3,titre:'Bilan ressources et limites planétaires',enonce:'À partir des "limites planétaires" (Rockström 2009), expliquer pourquoi notre modèle est insoutenable.',correction:'9 limites dont 6 déjà dépassées (2024) :\n→ Climat · Biodiversité · Azote+Phosphore · Utilisation des terres · Polluants · Eau\nPourquoi insoutenable : économie de croissance infinie sur planète finie · externalités non intégrées\nSolutions : économie du donut · décroissance sélective · comptabilité environnementale',notions:['Limites planétaires']},
    ]
  },
  {
    id:'immunite-premiere-svt', numero:6,
    titre:'Le système immunitaire humain',
    sousTitre:'Immunité innée · Adaptative · Anticorps · LT cytotoxiques · Vaccination',
    icon:'🛡️', color:'#8b5cf6',
    notions:['Immunité innée','Immunité adaptative','Anticorps','Vaccination'],
    exercices:[
      {id:'P6-01',difficulte:1,titre:'Immunité innée vs adaptative',enonce:'1. Différences.\n2. Laquelle est la plus rapide.\n3. Laquelle a une mémoire immunologique.',correction:'1. Innée : non spécifique · immédiate · même réponse. Adaptative : spécifique · lente (1ère fois) · mémoire\n2. Innée : minutes à heures. Adaptative : 5-15 jours\n3. L\'adaptative (cellules mémoires persistent des années)',notions:['Types immunité']},
      {id:'P6-02',difficulte:1,titre:'Phagocytose — étapes',enonce:'Décrire les 5 étapes de la phagocytose d\'une bactérie par un macrophage.',correction:'1. Chimiotactisme (attiré par cytokines)\n2. Reconnaissance (PRR reconnaissent PAMP bactériens)\n3. Adhérence\n4. Ingestion → phagosome\n5. Digestion (lysosome). Fragments présentés sur CMH II',notions:['Phagocytose']},
      {id:'P6-03',difficulte:1,titre:'Anticorps — structure',enonce:'1. Structure d\'un anticorps.\n2. Paratope vs épitope.\n3. 3 mécanismes d\'action.',correction:'1. Protéine en Y : 2 chaînes lourdes + 2 légères. Régions variables (Fab) + constante (Fc)\n2. Paratope : site de liaison de l\'Ac. Épitope : partie de l\'Ag reconnue\n3. Neutralisation · Opsonisation · Activation du complément',notions:['Anticorps']},
      {id:'P6-04',difficulte:2,titre:'LB et immunité humorale',enonce:'1. Comment un LB est activé.\n2. Prolifération clonale.\n3. Plasmocyte vs cellule mémoire B.',correction:'1. Reconnaissance Ag par BCR + signal LT CD4 → activation\n2. LB activé se divise → clone de milliers de LB identiques\n3. Plasmocyte : usine à Ac (1000/s) · vie courte. Mémoire B : survie longue (années)',notions:['Immunité humorale']},
      {id:'P6-05',difficulte:2,titre:'LT cytotoxiques',enonce:'1. Rôle des LT CD8.\n2. Comment reconnaissent-ils les cellules infectées.\n3. Mécanismes de destruction.',correction:'1. Détruire les cellules infectées par virus ou tumorales\n2. Reconnaissent fragments viraux sur CMH I (toutes les cellules nucléées)\n3. Libération perforine (perce la membrane) + granzymes (induisent apoptose)',notions:['LT cytotoxiques']},
      {id:'P6-06',difficulte:2,titre:'LT CD4 — chef d\'orchestre',enonce:'1. Rôle des LT CD4.\n2. Pourquoi le VIH est si dévastateur.\n3. Que se passe-t-il en cas de chute des LT CD4.',correction:'1. Sécrète cytokines activant LB et LT CD8 · chef d\'orchestre de la réponse adaptative\n2. VIH infecte spécifiquement LT CD4 → les détruit → effondrement immunité\n3. < 200 LT CD4/µL = SIDA → infections opportunistes + cancers',notions:['LT CD4','VIH']},
      {id:'P6-07',difficulte:2,titre:'Vaccination — principe',enonce:'1. Principe biologique.\n2. Primaire vs secondaire.\n3. Types de vaccins.',correction:'1. Ag inoffensif → réponse adaptative → cellules mémoires → réponse secondaire rapide\n2. Primaire : lente (5-15j) · faible [Ac]. Secondaire : rapide (2-5j) · forte [Ac] · IgG haute affinité\n3. Atténués · Inactivés · Sous-unitaires · ARNm (COVID) · Vecteur viral',notions:['Vaccination']},
      {id:'P6-08',difficulte:2,titre:'Immunité collective',enonce:'1. Définir.\n2. Pourquoi 95% contre la rougeole.\n3. Conséquences couverture insuffisante.',correction:'1. Assez de personnes immunisées → virus ne circule plus → protection des non vaccinés\n2. R0 = 12-18 → il faut immuniser 1 - 1/R0 = 92-95%\n3. Recrudescence maladies éradiquées (rougeole 2018-19 en Europe)',notions:['Immunité collective']},
      {id:'P6-09',difficulte:3,titre:'VIH et échappement immunitaire',enonce:'1. Comment le VIH échappe à l\'immunité.\n2. Pourquoi difficile de développer un vaccin.\n3. Comment fonctionnent les antirétroviraux.',correction:'1. Taux de mutation élevé · se cache dans LT CD4 latents · détruit l\'immunité\n2. Variabilité extrême de l\'enveloppe → pas d\'Ac universel. Réservoir latent\n3. Inhibiteurs transcriptase inverse · protéase · intégrase → charge virale < 40 copies/mL',notions:['VIH','ARV']},
      {id:'P6-10',difficulte:2,titre:'Maladies auto-immunes',enonce:'1. Définir.\n2. 3 exemples.\n3. Mécanisme + facteurs déclenchants.',correction:'1. Le SI attaque les propres cellules de l\'organisme\n2. SEP (myéline) · Diabète type 1 (cellules β) · Polyarthrite rhumatoïde\n3. LT auto-réactifs échappent à la sélection thymique. Facteurs : génétiques + infection (mimétisme moléculaire)',notions:['Auto-immunes']},
      {id:'P6-11',difficulte:2,titre:'Allergies',enonce:'1. Définir allergie.\n2. Mécanisme immunologique.\n3. Pourquoi allergies augmentent dans pays développés.',correction:'1. Réaction immunitaire exagérée à un Ag normalement inoffensif (allergène)\n2. Sensibilisation → IgE fixées sur mastocytes → 2ème expo → dégranulation → histamine → symptômes\n3. Hypothèse hygiéniste : moins d\'infections → SI sous-stimulé → réagit à des Ag inoffensifs',notions:['Allergies']},
      {id:'P6-12',difficulte:3,titre:'Immuno-thérapie anti-cancéreuse',enonce:'1. Pourquoi le SI ne détruit-il pas toujours les tumeurs.\n2. Check-points immunitaires.\n3. Comment les inhibiteurs (anti-PD1) fonctionnent.',correction:'1. Surexpression PD-L1 · perte CMH I · microenvironnement immunosuppresseur\n2. Molécules freinant l\'activation des LT (CTLA-4, PD-1/PD-L1) pour éviter l\'auto-immunité\n3. Anti-PD1 (nivolumab) bloque le frein → LTc attaquent à nouveau les tumeurs',notions:['Immunothérapie']},
      {id:'P6-13',difficulte:2,titre:'Transplantation et rejet',enonce:'1. Pourquoi peut-on rejeter un organe.\n2. Rôle du système HLA.\n3. Comment les immunosuppresseurs préviennent le rejet.',correction:'1. LT reconnaissent HLA du donneur comme "non-soi" → réponse immune → destruction\n2. HLA = CMH humain · très polymorphe → compatibilité HLA = typage avant transplantation\n3. Ciclosporine (inhibe LT CD4) · Tacrolimus · Corticoïdes → réduisent réponse immune',notions:['Transplantation']},
      {id:'P6-14',difficulte:2,titre:'Test ELISA',enonce:'1. Principe du test ELISA.\n2. Utilisations médicales.\n3. ELISA+ signifie quoi.',correction:'1. Ag fixé sur support → sérum patient → si Ac spécifiques → révélation enzymatique colorée\n2. Sérologie VIH · hépatite B/C · toxoplasmose · test grossesse (HCG)\n3. Le patient a des Ac contre cet Ag → exposition passée ou vaccination (pas forcément maladie active)',notions:['ELISA']},
      {id:'P6-15',difficulte:3,titre:'Mémoire immunitaire et durée',enonce:'1. Durée de la mémoire immunitaire.\n2. Pourquoi des rappels.\n3. Immunosénescence.',correction:'1. Variable : rougeole → vie entière. Grippe → 6-12 mois. VZV → décennies\n2. Mémoire diminue · virus évolue · certains vaccins induisent immunité courte\n3. Avec l\'âge : thymus diminue · répertoire LT réduit · moins bonne réponse aux nouveaux Ag',notions:['Mémoire immunitaire']},
      {id:'P6-16',difficulte:2,titre:'Interférons',enonce:'1. Définir interféron.\n2. Mécanisme antiviral.\n3. Utilisation médicale.',correction:'1. Cytokines produites par cellules infectées → signalent le danger viral aux voisines\n2. IFN-α/β → état antiviral des cellules voisines (ARNases dégradent ARN viral)\n3. Hépatite B/C · Sclérose en plaques (IFN-β) · certains cancers',notions:['Interférons']},
      {id:'P6-17',difficulte:3,titre:'Immunodéficiences primaires',enonce:'1. Définir.\n2. Exemple célèbre.\n3. Traitement.',correction:'1. Déficit congénital du SI (génétique) → infections répétées\n2. David Vetter "l\'enfant bulle" (SCID : pas de LT ni LB)\n3. Immunoglobulines IV · greffe de moelle · thérapie génique (Strimvelis 2016, 1er en Europe)',notions:['Immunodéficiences']},
      {id:'P6-18',difficulte:2,titre:'Sérothérapie vs vaccination',enonce:'1. Différence.\n2. Quand utilise-t-on la sérothérapie.\n3. Exemples.',correction:'1. Vaccination : active (mémoire + durable). Sérothérapie : passive (Ac tout faits → immédiat mais temporaire)\n2. Urgences · immunodéprimés · contact avec maladie grave\n3. Sérum antivenimeux · Ig anti-tétanos · Ac monoclonaux anti-COVID',notions:['Sérothérapie']},
      {id:'P6-19',difficulte:2,titre:'Le système du complément',enonce:'1. Définir.\n2. Comment activé.\n3. Ses 3 fonctions.',correction:'1. Cascade de protéines plasmatiques renforçant l\'action des Ac et des phagocytes\n2. Voie classique : Ac+Ag → C1. Voie alterne : surfaces bactériennes. Voie lectine : sucres bactériens\n3. Lyse bactérienne (MAC) · Opsonisation (C3b) · Chimiotactisme (C3a, C5a)',notions:['Complément']},
      {id:'P6-20',difficulte:3,titre:'Bilan système immunitaire',enonce:'Comment le SI distingue-t-il le soi du non-soi ? Conséquences quand cela déraille.',correction:'SÉLECTION THYMIQUE : LT auto-réactifs éliminés ou → Treg\nCMH I : présente "soi". Si peptide étranger → LT CD8 détruit\nRécepteurs de tolérance (CTLA-4, PD-1) → freinent LT auto-réactifs\n\nDYSFONCTIONNEMENTS :\n→ Auto-immunes · Allergies · Immunodéficiences · Rejet de greffe',notions:['Bilan immunité']},
    ]
  },
  {
    id:'genetique-sante-premiere-svt', numero:7,
    titre:'Variation génétique & Santé',
    sousTitre:'Génétique mendélienne · Maladies génétiques · Cancer · Caryotype',
    icon:'🔭', color:'#ec4899',
    notions:['Génétique mendélienne','Maladies génétiques','Cancer','Caryotype'],
    exercices:[
      {id:'P7-01',difficulte:1,titre:'Lois de Mendel',enonce:'1. Loi de ségrégation.\n2. Loi d\'assortiment indépendant.\n3. Quand la 2ème loi ne s\'applique-t-elle pas.',correction:'1. Les 2 allèles se séparent lors de la méiose → chaque gamète reçoit 1 seul allèle\n2. Les allèles de gènes différents se séparent indépendamment (chromosomes différents)\n3. Si 2 gènes sont liés (même chromosome) → ségrégation non indépendante',notions:['Lois Mendel']},
      {id:'P7-02',difficulte:1,titre:'Génotype et phénotype',enonce:'1. Définir génotype, phénotype, allèle.\n2. Dominant vs récessif.\n3. Même génotype → phénotypes différents ?',correction:'1. Génotype : constitution allélique. Phénotype : caractère observable. Allèle : version d\'un gène\n2. Dominant : s\'exprime en 1 copie. Récessif : 2 copies nécessaires\n3. Oui : pénétrance incomplète · expressivité variable · environnement',notions:['Génotype/Phénotype']},
      {id:'P7-03',difficulte:2,titre:'Mucoviscidose — hérédité',enonce:'Parents porteurs sains (Cc × Cc).\n1. Tableau de Punnett.\n2. Probabilité enfant malade.\n3. Porteur sain.',correction:'CC(25%) · Cc(50%) · cc(25%)\n1. Grille : CC, Cc, Cc, cc\n2. P(malade) = 25%\n3. P(porteur) = 50% (autosomique récessive)',notions:['Mucoviscidose']},
      {id:'P7-04',difficulte:2,titre:'Drépanocytose — codominance',enonce:'HbA/HbS × HbA/HbS.\n1. Génotypes des enfants.\n2. Phénotypes.\n3. Avantage hétérozygote.',correction:'HbA/HbA (25%) · HbA/HbS (50%) · HbS/HbS (25%)\n2. Normal · porteur sain (résiste paludisme) · malade\n3. HbA/HbS résiste mieux au paludisme → maintien allèle HbS en Afrique',notions:['Codominance']},
      {id:'P7-05',difficulte:2,titre:'Hérédité liée au sexe',enonce:'Mère conductrice (XᵐX) × père sain (XY).\n1. Probabilité fils malade.\n2. Fille conductrice.\n3. Pourquoi filles rarement malades.',correction:'Xᵐ X(25%) · XX(25%) · XᵐY(25%) · XY(25%)\n1. 50% des fils\n2. 50% des filles\n3. Deux chromosomes X → une copie normale masque l\'allèle récessif',notions:['Hérédité liée sexe']},
      {id:'P7-06',difficulte:2,titre:'Caryotype et trisomie 21',enonce:'1. Définir caryotype.\n2. Trisomie 21.\n3. Mécanisme de la non-disjonction.',correction:'1. Représentation ordonnée des chromosomes → détecte anomalies\n2. 47 chromosomes : 3 chr 21 → syndrome de Down\n3. Chr 21 homologues ne se séparent pas (anaphase I) → gamète avec 2 chr 21',notions:['Caryotype','Trisomie']},
      {id:'P7-07',difficulte:3,titre:'Cancer — deux coups de Knudson',enonce:'BRCA1 muté en hétérozygote.\n1. Dominant ou récessif.\n2. Modèle deux coups.\n3. Risque 72% vs 12% population générale.',correction:'1. Récessif (suppresseur de tumeur = perte de fonction)\n2. 1er coup héréditaire (toutes les cellules). 2ème coup : mutation somatique dans cellule mammaire → 2 copies inactivées → cancer\n3. 1er coup déjà présent → 1 seul coup aléatoire suffit → très probable sur 70 ans de vie',notions:['BRCA1','Deux coups']},
      {id:'P7-08',difficulte:2,titre:'Diagnostic prénatal',enonce:'1. 3 techniques de diagnostic prénatal.\n2. À quoi sert l\'amniocentèse.\n3. DPN vs DPI.',correction:'1. Amniocentèse · Biopsie trophoblaste (CVS) · NIPT (ADN fœtal dans sang maternel)\n2. Prélèvement liquide amniotique → cellules fœtales → caryotype + génétique moléculaire\n3. DPN : après fécondation in vivo. DPI : sur embryon FIV avant implantation → sélection',notions:['Diagnostic prénatal']},
      {id:'P7-09',difficulte:2,titre:'Phénylcétonurie',enonce:'1. Définir PCU.\n2. Pourquoi le régime traite la maladie.\n3. Pourquoi dépistage à la naissance.',correction:'1. Déficit en PAH → accumulation Phe → toxique pour le cerveau\n2. Sans Phe dans l\'alimentation → pas d\'accumulation → développement normal\n3. Test de Guthrie → diagnostic avant symptômes → régime immédiat → développement NORMAL',notions:['PCU']},
      {id:'P7-10',difficulte:3,titre:'Thérapie génique',enonce:'1. Définir.\n2. Vecteurs utilisés.\n3. Exemple réussi + limites.',correction:'1. Introduction d\'une séquence d\'ADN thérapeutique dans les cellules\n2. Vecteurs viraux (lentivirus, AAV) · non viraux (nanoparticules lipidiques)\n3. ADA-SCID (Strimvelis 2016). Limites : coût 1-3 M€ · risque oncogènes · immunité anti-vecteur',notions:['Thérapie génique']},
      {id:'P7-11',difficulte:2,titre:'Hardy-Weinberg appliqué',enonce:'0,04% malades d\'une maladie récessive (aa).\nCalculer q, p et fréquence des porteurs.',correction:'q² = 0,0004 → q = 0,02\np = 0,98\nPorteurs sains 2pq = 2×0,98×0,02 = 3,9% (~1/25)',notions:['Hardy-Weinberg']},
      {id:'P7-12',difficulte:2,titre:'Syndromes chromosomiques sexuels',enonce:'1. Turner (45,X). 2. Klinefelter (47,XXY). 3. Pourquoi affectent surtout la reproduction.',correction:'1. Turner : femme · petite taille · ovaires atrophiés · aménorrhée · monosomie X\n2. Klinefelter : homme · gynécomastie · petits testicules · azoospermie · trisomie sexuelle\n3. Chr sexuels portent gènes essentiels au développement des gonades → anomalie → stérilité',notions:['Syndromes chromosomiques']},
      {id:'P7-13',difficulte:3,titre:'CRISPR-Cas9',enonce:'1. Principe.\n2. Applications médicales.\n3. Enjeux éthiques.',correction:'1. ARN guide → Cas9 → coupe les 2 brins à la cible → réparation\n2. Casgevy (FDA 2023, drépanocytose) · bêta-thalassémie · cancers\n3. Modifications germinales héritables · sécurité off-target · accès équitable (2 M€)',notions:['CRISPR-Cas9']},
      {id:'P7-14',difficulte:2,titre:'Hérédité polygénique',enonce:'1. Définir.\n2. Exemples.\n3. Pourquoi distribution normale.',correction:'1. Caractère contrôlé par de nombreux gènes contribuant chacun un peu\n2. Taille · couleur de peau · poids · pression artérielle\n3. Loi des grands nombres → distribution en cloche (gaussienne)',notions:['Polygénique']},
      {id:'P7-15',difficulte:2,titre:'Empreinte génomique',enonce:'1. Définir l\'empreinte génomique.\n2. Exemple : gène Igf2.\n3. Conséquences d\'une anomalie.',correction:'1. Certains gènes n\'expriment qu\'une seule copie selon le parent d\'origine (méthylation différentielle)\n2. Igf2 : exprimé uniquement depuis chr paternel\n3. Prader-Willi (absence gènes paternels chr 15) · Angelman (maternels) → syndromes totalement différents',notions:['Imprinting']},
      {id:'P7-16',difficulte:3,titre:'Pharmacogénomique',enonce:'1. Définir.\n2. Exemple de gène influençant le métabolisme d\'un médicament.\n3. Applications cliniques.',correction:'1. Étude de l\'influence des variations génétiques sur la réponse aux médicaments\n2. CYP2D6 : métabolise codéine en morphine. Lents → toxicité · Rapides → pas d\'effet\n3. Adapter molécule ET dose au génotype. Oncologie : Herceptine uniquement si HER2+',notions:['Pharmacogénomique']},
      {id:'P7-17',difficulte:2,titre:'Méiose et diversité génétique',enonce:'1. Comment la méiose génère de la diversité.\n2. Nombre de gamètes possibles chez l\'humain.\n3. Impact du crossing-over.',correction:'1. Brassage interchromosomique + intrachromosomique (crossing-over)\n2. 2²³ = 8 388 608 types de gamètes (brassage interchromosomique seul)\n3. Gamètes recombinants → diversité supplémentaire illimitée',notions:['Méiose et diversité']},
      {id:'P7-18',difficulte:2,titre:'Séquençage et NGS',enonce:'1. Définir séquençage (méthode Sanger).\n2. NGS : avantage.\n3. Application en oncologie.',correction:'1. ddNTP terminateurs → fragments de longueurs différentes → séquence\n2. Millions de fragments simultanément → génome entier en 24h pour ~1000€\n3. Séquençage de la tumeur → mutations conductrices → thérapie ciblée (ex: EGFR → erlotinib)',notions:['Séquençage']},
      {id:'P7-19',difficulte:3,titre:'Épigénétique et maladie',enonce:'1. Mécanismes épigénétiques.\n2. Comment l\'environnement modifie l\'épigénome.\n3. Transmissible à la descendance ?',correction:'1. Méthylation ADN · Acétylation histones · ARN non codants\n2. Alimentation · tabac · stress · activité physique. "Dutch Hunger Winter" → épigénome altéré chez les descendants\n3. Débattu : certaines marques effacées à la fécondation, pas toutes → transmission partielle possible',notions:['Épigénétique']},
      {id:'P7-20',difficulte:3,titre:'Bilan génétique et médecine',enonce:'Comment la génétique a-t-elle transformé la médecine en 50 ans ?',correction:'1. DIAGNOSTIC : identification moléculaire de milliers de maladies. Dépistage néonatal → millions d\'enfants normaux\n2. TRAITEMENT : Gleevec (LMC 2001) · Strimvelis (2016) · Casgevy CRISPR (2023)\n3. PRÉVENTION : tests BRCA, Lynch → surveillance renforcée · DPI → embryons sains\n4. DÉFIS : maladies polygéniques · accès inégal · éthique (discrimination génétique)',notions:['Bilan génétique']},
    ]
  },
  {
    id:'systeme-nerveux-premiere-svt', numero:8,
    titre:'Fonctionnement du système nerveux',
    sousTitre:'Neurone · Potentiel d\'action · Synapse · Plasticité · Addictions',
    icon:'🧠', color:'#6366f1',
    notions:['Neurone','Potentiel d\'action','Synapse','Plasticité'],
    exercices:[
      {id:'P8-01',difficulte:1,titre:'Structure du neurone',enonce:'1. Décrire un neurone moteur.\n2. Dendrites vs axone.\n3. Gaine de myéline et rôle.',correction:'1. Soma + Dendrites + Axone + Gaine de myéline + Boutons synaptiques\n2. Dendrites REÇOIVENT. Axone TRANSMET\n3. Cellules de Schwann → isolant → conduction saltatoire → 100× plus rapide',notions:['Neurone']},
      {id:'P8-02',difficulte:1,titre:'Potentiel de repos',enonce:'1. Valeur du potentiel de repos.\n2. Pompe qui le maintient.\n3. Distribution Na⁺ et K⁺.',correction:'1. -70 mV (intérieur négatif)\n2. Pompe Na⁺/K⁺ ATPase : 3 Na⁺ sortent / 2 K⁺ entrent\n3. Na⁺ : surtout extérieur. K⁺ : surtout intérieur',notions:['Potentiel de repos']},
      {id:'P8-03',difficulte:2,titre:'Potentiel d\'action — ionique',enonce:'Décrire les phases du PA et les mouvements ioniques.',correction:'1. Dépolarisation : canaux Na⁺ s\'ouvrent → afflux Na⁺ → -70 → +30 mV\n2. Repolarisation : Na⁺ se ferment + K⁺ s\'ouvrent → sortie K⁺ → retour -70 mV\n3. Hyperpolarisation : légère sous-oscillation → période réfractaire',notions:['Potentiel d\'action']},
      {id:'P8-04',difficulte:1,titre:'Loi du tout ou rien',enonce:'1. Énoncer la loi.\n2. Seuil de déclenchement.\n3. Comment l\'intensité est codée.',correction:'1. En dessous du seuil : pas de PA. Au-dessus : PA identique en amplitude\n2. ~-55 mV\n3. Par la FRÉQUENCE des PA (Hz) · pas l\'amplitude',notions:['Loi tout ou rien']},
      {id:'P8-05',difficulte:2,titre:'Synapse chimique',enonce:'Décrire le fonctionnement d\'une synapse de l\'arrivée du PA au signal post-synaptique.',correction:'1. PA → bouton présynaptique\n2. Canaux Ca²⁺ s\'ouvrent\n3. Vésicules fusionnent → exocytose NT dans la fente\n4. NT fixe récepteurs post-synaptiques\n5. PPSE (Na⁺ entrant) ou PPSI (Cl⁻/K⁺)\n6. NT dégradé ou recapturé',notions:['Synapse chimique']},
      {id:'P8-06',difficulte:2,titre:'Neurotransmetteurs et cocaïne',enonce:'1. 4 neurotransmetteurs majeurs et fonctions.\n2. Comment la cocaïne agit sur la synapse dopaminergique.\n3. Pourquoi cela provoque de la dépendance.',correction:'1. Acétylcholine (mémoire) · Dopamine (récompense) · Sérotonine (humeur) · GABA (inhibition)\n2. Cocaïne bloque DAT → dopamine reste dans fente → euphorie intense\n3. Neuroadaptation → tolérance → manque dopamine → dépression → compulsion',notions:['Neurotransmetteurs']},
      {id:'P8-07',difficulte:2,titre:'Plasticité synaptique et mémoire',enonce:'1. Définir plasticité synaptique.\n2. LTP.\n3. Lien avec l\'apprentissage.',correction:'1. Capacité des synapses à modifier leur efficacité en réponse à l\'activité\n2. LTP : renforcement durable après activation répétée → + récepteurs AMPA + NT libérés\n3. Apprentissage = répétition → LTP → circuits plus efficaces. "Neurones qui s\'activent ensemble se connectent"',notions:['Plasticité','LTP']},
      {id:'P8-08',difficulte:2,titre:'Sclérose en plaques',enonce:'1. Définir SEP.\n2. Mécanisme immunologique.\n3. Conséquences sur la conduction.',correction:'1. Maladie auto-immune du SNC : attaque la myéline\n2. LT auto-réactifs traversent BHE → attaquent oligodendrocytes → démyélinisation\n3. Conduction saltatoire impossible → signal ralenti ou bloqué → paralysie, troubles visuels',notions:['SEP']},
      {id:'P8-09',difficulte:2,titre:'Maladie d\'Alzheimer',enonce:'1. Mécanismes cellulaires.\n2. Symptômes progressifs.\n3. Où commence la neurodégénérescence.',correction:'1. Dépôts β-amyloïde (plaques séniles) + tau hyperphosphorylée → mort neuronale\n2. Perte mémoire récente → désorientation → perte autonomie totale\n3. Commence par l\'hippocampe et cortex entorhinal',notions:['Alzheimer']},
      {id:'P8-10',difficulte:2,titre:'Maladie de Parkinson',enonce:'1. Neurones qui dégénèrent.\n2. Mécanisme menant aux symptômes moteurs.\n3. Traitement L-DOPA.',correction:'1. Neurones dopaminergiques de la substance noire\n2. Voie nigro-striée défaillante → "frein" sur le cortex moteur → difficultés à initier les mouvements\n3. Précurseur de la dopamine → passe la BHE → converti en dopamine → compense le déficit',notions:['Parkinson']},
      {id:'P8-11',difficulte:3,titre:'Morphine et dépendance',enonce:'1. Comment la morphine agit sur le cerveau.\n2. Pourquoi forte dépendance physique.\n3. Traitement de la dépendance.',correction:'1. Agoniste récepteurs opioïdes (μ) → mimik endorphines → analgésie + euphorie\n2. Neuroadaptation : réduction endorphines naturelles + récepteurs → manque physique intense\n3. Méthadone ou buprénorphine (Subutex) → contrôle le manque sans euphorie',notions:['Opioïdes']},
      {id:'P8-12',difficulte:2,titre:'Sommeil et cerveau',enonce:'1. Structures régulant le sommeil.\n2. Sommeil lent vs paradoxal.\n3. Rôles du sommeil.',correction:'1. Hypothalamus (SCN) · Tronc cérébral · Mélatonine (épiphyse)\n2. Lent : ondes lentes · récupération physique. Paradoxal : REM · rêves · consolidation procédurale\n3. Élimination β-amyloïde · consolidation mémorielle · régulation émotionnelle',notions:['Sommeil']},
      {id:'P8-13',difficulte:2,titre:'Organisation du cerveau',enonce:'1. 4 lobes et fonctions.\n2. Cortex moteur primaire.\n3. Cortex somatosensoriel.',correction:'1. Frontal (décision, langage moteur) · Pariétal (sensoriel) · Temporal (audition, mémoire) · Occipital (vision)\n2. Gyrus précentral : contrôle mouvements volontaires → somatotopique (homonculus)\n3. Gyrus postcentral : informations tactiles, proprioceptives, thermiques',notions:['Lobes cérébraux']},
      {id:'P8-14',difficulte:3,titre:'Dépression et ISRS',enonce:'1. Hypothèse monoaminergique de la dépression.\n2. Mécanisme des ISRS.\n3. Pourquoi délai d\'action de 2-4 semaines.',correction:'1. Déficit en sérotonine, noradrénaline et/ou dopamine\n2. ISRS bloquent SERT → sérotonine reste dans fente → + de stimulation\n3. D\'abord autorécepteurs 5-HT1A stimulés (frein). Après 2-4 sem : se désensibilisent → sérotonine agit vraiment',notions:['Dépression','ISRS']},
      {id:'P8-15',difficulte:2,titre:'Barrière hémato-encéphalique',enonce:'1. Définir BHE.\n2. Pourquoi importante.\n3. Comment les médicaments la franchissent.',correction:'1. Cellules endothéliales (jonctions serrées) + astrocytes → empêche la plupart des substances\n2. Protège le cerveau · maintient environnement ionique stable pour les neurones\n3. Molécules liposolubles (éthanol, THC) passent facilement. L-DOPA : transporteur spécifique',notions:['BHE']},
      {id:'P8-16',difficulte:2,titre:'Épilepsie',enonce:'1. Définir épilepsie et crise.\n2. Mécanisme neurologique.\n3. Classes d\'antiépileptiques.',correction:'1. Trouble neurologique : crises récurrentes = décharges électriques anormales synchrones\n2. Déséquilibre excitation/inhibition : trop de glutamate · trop peu de GABA\n3. Bloqueurs canaux Na⁺ (carbamazépine) · GABA-ergiques (valproate) · Bloqueurs canaux Ca²⁺',notions:['Épilepsie']},
      {id:'P8-17',difficulte:3,titre:'Cannabis et cerveau adolescent',enonce:'1. Système endocannabinoïde.\n2. Comment le THC agit.\n3. Effets sur le cerveau adolescent.',correction:'1. Anandamide + 2-AG → récepteurs CB1 (cerveau) + CB2 (immunité) → régule appétit, douleur, mémoire\n2. THC = agoniste partiel CB1 → perturbe transmission synaptique hippocampe + cortex préfrontal\n3. Myélinisation en cours jusqu\'à 25 ans → THC perturbe le développement → risque cognitif + psychotique',notions:['Cannabis']},
      {id:'P8-18',difficulte:2,titre:'Douleur et analgésie',enonce:'1. Circuit de la douleur.\n2. Théorie du portillon.\n3. Opioïdes vs ibuprofène.',correction:'1. Nocicepteurs → fibres Aδ/C → moelle → thalamus → cortex somatosensoriel\n2. Fibres Aβ activent interneurones inhibiteurs → "ferment" la transmission douloureuse\n3. Opioïdes : bloquent libération NT en corne dorsale + effets centraux. Ibuprofène : inhibe COX → moins prostaglandines',notions:['Douleur']},
      {id:'P8-19',difficulte:3,titre:'Neurogenèse adulte',enonce:'1. De nouveaux neurones se forment-ils chez l\'adulte.\n2. Dans quelles zones.\n3. Facteurs stimulant ou inhibant.',correction:'1. Oui (hippocampe bien établi chez souris, débattu chez l\'humain)\n2. Hippocampe (gyrus denté) · Bulbe olfactif\n3. Stimulent : exercice physique · environnement enrichi · antidépresseurs\nInhibent : stress chronique (cortisol) · alcool · vieillissement',notions:['Neurogenèse']},
      {id:'P8-20',difficulte:3,titre:'Bilan système nerveux',enonce:'Comment le SI intègre-t-il une piqûre du doigt jusqu\'à la réponse consciente ?',correction:'1. Nocicepteurs doigt → PA dans fibre Aδ\n2. Corne dorsale moelle → tractus spinothalamique → monte\n3. Thalamus (VPL) → distribue au cortex\n4. Cortex somatosensoriel S1 (localisation). Insula (émotion). Cortex cingulaire (souffrance)\n5. EN PARALLÈLE : arc réflexe → retrait AVANT la conscience\n6. Cortex moteur → retrait délibéré + "aïe !"',notions:['Intégration nerveuse']},
    ]
  },
  {
    id:'methodes-premiere-svt', numero:9,
    titre:'Méthodes scientifiques & ECE',
    sousTitre:'Démarche expérimentale · Statistiques · Modèles · Communication · ECE',
    icon:'🔬', color:'#06b6d4',
    notions:['Démarche expérimentale','Statistiques','ECE'],
    exercices:[
      {id:'P9-01',difficulte:1,titre:'Étapes de la démarche expérimentale',enonce:'Citer et décrire les 8 étapes.',correction:'1. Observation\n2. Problématique\n3. Hypothèse\n4. Protocole (matériel + variables + contrôle)\n5. Expérience\n6. Résultats (tableaux, graphiques)\n7. Analyse\n8. Interprétation et Conclusion',notions:['Démarche']},
      {id:'P9-02',difficulte:1,titre:'Variables en expérimentation',enonce:'Effet du pH sur la pepsine.\n1. Variable indépendante.\n2. Variable dépendante.\n3. Variables contrôlées.',correction:'1. Le pH\n2. L\'activité de la pepsine (concentration en AA libérés)\n3. Substrat · quantité de pepsine · température · durée',notions:['Variables']},
      {id:'P9-03',difficulte:1,titre:'Groupe contrôle',enonce:'1. Définir.\n2. Pourquoi indispensable.\n3. Exemple : antibiotiques sur bactéries.',correction:'1. Condition de référence sans la variable testée\n2. Sans lui, impossible d\'attribuer l\'effet à la variable testée\n3. Boîte sans antibiotique → pousse normalement. Avec → si moins de croissance = dû à l\'antibiotique',notions:['Groupe contrôle']},
      {id:'P9-04',difficulte:2,titre:'Construire un graphique scientifique',enonce:'Règles pour "photosynthèse en fonction de l\'intensité lumineuse".',correction:'1. Titre explicite\n2. Axe X : variable indépendante + unité\n3. Axe Y : variable mesurée + unité\n4. Échelles régulières\n5. Points + courbe lissée\n6. Légende si plusieurs courbes\n7. Source',notions:['Graphiques']},
      {id:'P9-05',difficulte:2,titre:'Analyser un graphique de photosynthèse',enonce:'0 lux : -2 µmol/h. 500 lux : 0. 2000 lux : 5 (plateau).\n1. Interpréter les 3 valeurs.\n2. Point de compensation.\n3. Saturation lumineuse.',correction:'1. 0 : respiration seule (-2). 500 : photo = respiration (0). 2000 : photo maximale (autre facteur limite)\n2. 500 lux : photo = respiration → bilan net = 0\n3. 2000 lux : plus de lumière n\'augmente plus la photo',notions:['Analyse graphique']},
      {id:'P9-06',difficulte:2,titre:'Calcul de Rf en chromatographie',enonce:'Solvant : 8 cm. Pigment A : 6,4 cm. Pigment B : 2,4 cm.\nChlorophylle a : Rf≈0,85 · b : Rf≈0,45.',correction:'Rf(A) = 6,4/8,0 = 0,80 ≈ 0,85 → CHLOROPHYLLE a\nRf(B) = 2,4/8,0 = 0,30 ≈ 0,45 → CHLOROPHYLLE b',notions:['Rf','Chromatographie']},
      {id:'P9-07',difficulte:2,titre:'Statistiques descriptives',enonce:'5 mesures : 12 · 14 · 11 · 13 · 15 cm\n1. Moyenne.\n2. Écart-type.\n3. Écart-type élevé signifie ?',correction:'1. Moyenne = 13 cm\n2. σ = √[Σ(xᵢ-x̄)²/n] = √(10/5) = √2 ≈ 1,41 cm\n3. Grande variabilité des données · mesures peu précises ou échantillon hétérogène',notions:['Statistiques']},
      {id:'P9-08',difficulte:2,titre:'Test statistique simplifié',enonce:'Groupe A : 85±5 g. Groupe B : 70±8 g.\n1. Différences significatives.\n2. Valeur p.\n3. Seuil de significativité.',correction:'1. IC A : [75-95] · IC B : [54-86] → chevauchement limité → probablement significative\n2. Probabilité d\'obtenir résultats aussi extrêmes par hasard si H0 vraie\n3. p < 0,05 → significatif (rejet de H0)',notions:['Test statistique']},
      {id:'P9-09',difficulte:2,titre:'Modèles scientifiques',enonce:'1. Définir modèle scientifique.\n2. Avantages et limites.\n3. Exemple en SVT.',correction:'1. Représentation simplifiée d\'un système réel → comprendre, prédire, simuler\n2. Avantages : simplification · prédictions testables. Limites : certains facteurs omis · valide sous certaines conditions\n3. Modèle de Watson-Crick · Modèle logistique de population · GCM climatique',notions:['Modèles']},
      {id:'P9-10',difficulte:3,titre:'ECE — préparation lame microscopique',enonce:'Protocole complet pour observer l\'épiderme d\'oignon.',correction:'1. Prélever épiderme (tunique interne)\n2. Étaler sur lame + eau\n3. Coloration bleu de méthylène (1 min)\n4. Rincer\n5. Lamelle sans bulles\n6. Éponger l\'excès\n7. Observation ×40 → ×100 → ×400\n8. Mise au point : vis macrométrique puis micrométrique',notions:['Protocole microscopie']},
      {id:'P9-11',difficulte:2,titre:'Interprétation données enzymatiques',enonce:'Amylase : 20°C=0,5 · 37°C=2,8 · 55°C=0,2 · 70°C=0 µmol/min.\nAnalyser.',correction:'DESCRIPTION : faible à 20°C · maximale à 37°C · chute brutale après · nulle à 70°C\nINTERPRÉTATION : 37°C = optimum (T° corporelle humaine).\n> 37°C : dénaturation (perte conformation 3D)\n70°C : irréversible',notions:['Interprétation données']},
      {id:'P9-12',difficulte:2,titre:'Compte-rendu de TP',enonce:'Structure d\'un compte-rendu de TP en SVT.',correction:'1. Titre + objectif\n2. Matériel et méthode\n3. Résultats (schémas, tableaux, photos)\n4. Analyse (objectif)\n5. Interprétation (biologique)\n6. Conclusion\n7. Sources d\'erreur + discussion',notions:['Compte-rendu']},
      {id:'P9-13',difficulte:3,titre:'ECE — spectrophotométrie',enonce:'1. Principe (Beer-Lambert).\n2. Mesurer l\'activité d\'une catalase.\n3. Déduire l\'activité de la courbe.',correction:'1. A = ε × l × c → absorbance proportionnelle à la concentration\n2. H₂O₂ + catalase → H₂O + O₂. Mesurer disparition H₂O₂ par spectrophotomètre\n3. Courbe [produit] = f(temps) → pente initiale = vitesse initiale = activité enzymatique',notions:['Spectrophotométrie']},
      {id:'P9-14',difficulte:2,titre:'Biais expérimentaux',enonce:'1. Définir biais expérimental.\n2. 3 types fréquents.\n3. Comment les éviter.',correction:'1. Erreur systématique faussant les résultats dans un sens\n2. Sélection · Observateur · Confirmation · Mesure\n3. Double aveugle · Randomisation · Calibration instruments · Préregistration',notions:['Biais expérimentaux']},
      {id:'P9-15',difficulte:2,titre:'Extraction d\'ADN',enonce:'Protocole extraction ADN de kiwi.\n1. Rôle du sel.\n2. Rôle du détergent.\n3. Rôle de l\'éthanol froid.',correction:'1. NaCl : neutralise charges négatives ADN → maintient en solution\n2. Détergent : lyse membranes → libère contenu cellulaire\n3. Éthanol froid : ADN insoluble → précipite → visible à l\'œil nu (filaments blancs)',notions:['Extraction ADN']},
      {id:'P9-16',difficulte:2,titre:'Dissection et éthique',enonce:'1. Quand est-il justifié de disséquer.\n2. Les 3R.\n3. Alternatives.',correction:'1. Objectif pédagogique clair + pas d\'alternative équivalente + espèce non protégée\n2. Remplacer · Réduire · Raffiner (Russell et Burch 1959)\n3. Modèles 3D · simulations numériques · vidéos · cultures cellulaires',notions:['Éthique']},
      {id:'P9-17',difficulte:3,titre:'Expérience de Meselson et Stahl',enonce:'1. Principe.\n2. Résultats.\n3. Ce qu\'elle prouve.',correction:'1. ¹⁵N puis ¹⁴N → centrifugation en gradient CsCl à différentes générations\n2. G0 : 1 bande lourde. G1 : 1 bande intermédiaire. G2 : intermédiaire + légère (1:1)\n3. PREUVE de la réplication SEMI-CONSERVATIVE : 1 brin parental + 1 néosynthétisé',notions:['Méselson et Stahl']},
      {id:'P9-18',difficulte:2,titre:'Lecture d\'un article scientifique',enonce:'1. Structure d\'un article (IMRaD).\n2. Comment lire efficacement.\n3. Peer-review.',correction:'1. Introduction · Methods · Results · Discussion (+ Conclusion)\n2. Titre+résumé → figures → conclusion → méthodes → texte complet\n3. Experts évaluent anonymement avant publication → garantie de qualité',notions:['Article scientifique']},
      {id:'P9-19',difficulte:3,titre:'Fraude scientifique',enonce:'1. Définir.\n2. Exemple célèbre.\n3. Comment détectée.',correction:'1. Fabrication (inventer données) · Falsification · Plagiat\n2. Wakefield (1998) : lien frauduleux vaccin-autisme → retiré du Lancet → méfiance vaccinale\n3. Réplication par d\'autres équipes · analyse statistique (données trop parfaites) · lanceurs d\'alerte',notions:['Fraude scientifique']},
      {id:'P9-20',difficulte:3,titre:'Bilan méthodes scientifiques',enonce:'Pourquoi la rigueur méthodologique est-elle essentielle en biologie ? 3 exemples.',correction:'1. MÉDECINE : sans RCT → thalidomide → 10 000 bébés malformés\n2. VACCINS : Wakefield (1 étude biaisée) → méfiance → épidémies rougeole. Méta-analyses nécessaires\n3. CHANGEMENT CLIMATIQUE : consensus 97% climatologues basé sur centaines de milliers de mesures\n→ La science n\'est pas parfaite mais s\'auto-corrige → méthode la plus fiable',notions:['Rigueur scientifique']},
    ]
  },
]

const CHAPITRES_SECONDE_SVT: ChapitreData[] = [
  {
    id:'cellules-seconde-svt', numero:1,
    titre:'La cellule — unité du vivant',
    sousTitre:'Cellule animale · Végétale · Organites · Différenciation · Microscope',
    icon:'🔬', color:'#22c55e',
    notions:['Cellule animale','Cellule végétale','Organites','Différenciation','Microscope'],
    exercices:[
      {id:'SV1-01',difficulte:1,titre:'Animale vs végétale',enonce:'1. 3 organites communs.\n2. 3 structures exclusives cellule végétale.\n3. Pourquoi verte ?',correction:'1. Noyau · Mitochondries · Membrane plasmique\n2. Paroi cellulosique · Chloroplastes · Grande vacuole centrale\n3. Chlorophylle dans les chloroplastes',notions:['Cellule']},
      {id:'SV1-02',difficulte:1,titre:'Rôle des organites',enonce:'Associer : Noyau · Mitochondrie · Chloroplaste · Ribosome · Vacuole → fonction.',correction:'Noyau → ADN, contrôle\nMitochondrie → ATP (respiration)\nChloplaste → photosynthèse\nRibosome → synthèse protéines\nVacuole → stockage eau/déchets',notions:['Organites']},
      {id:'SV1-03',difficulte:1,titre:'Grandissement',enonce:'Obj ×40, ocul ×10.\n1. G total.\n2. GR mesure 0,7 cm sur schéma → taille réelle.\n3. En µm.',correction:'1. G = 400\n2. 0,7/400 = 0,00175 cm = 17,5 µm\n3. 17,5 µm',notions:['Microscope']},
      {id:'SV1-04',difficulte:1,titre:'Membrane plasmique',enonce:'1. Rôle.\n2. Membrane semi-perméable.\n3. Composition principale.',correction:'1. Délimite + contrôle les échanges\n2. Laisse passer certaines molécules (eau, petites) mais pas d\'autres\n3. Double couche de phospholipides + protéines',notions:['Membrane']},
      {id:'SV1-05',difficulte:1,titre:'ADN dans la cellule',enonce:'1. Où se trouve l\'ADN dans une cellule eucaryote ?\n2. Fonction principale.\n3. Définir gène.',correction:'1. Noyau (chromosomes) + mitochondries + chloroplastes\n2. Information génétique → guide fabrication des protéines\n3. Séquence d\'ADN codant pour une protéine',notions:['ADN']},
      {id:'SV1-06',difficulte:2,titre:'Différenciation cellulaire',enonce:'Neurone et globule rouge ont le même ADN.\n1. Pourquoi si différents ?\n2. Expression différentielle des gènes.\n3. 2 autres types cellulaires différenciés.',correction:'1. N\'expriment pas les mêmes gènes → protéines différentes\n2. Certains gènes activés, d\'autres silencieux selon le type cellulaire\n3. Cellule musculaire · hépatocyte · lymphocyte',notions:['Différenciation']},
      {id:'SV1-07',difficulte:2,titre:'Tissu et organe',enonce:'1. Définir tissu et organe.\n2. Tissus composant le cœur.\n3. Tissu permettant la contraction musculaire.',correction:'1. Tissu = cellules semblables même fonction. Organe = tissus organisés\n2. Musculaire cardiaque + conjonctif + nerveux + épithélium\n3. Tissu musculaire',notions:['Tissu','Organe']},
      {id:'SV1-08',difficulte:2,titre:'Colorations histologiques',enonce:'1. Bleu de méthylène.\n2. Lugol.\n3. Pourquoi pas d\'organites au microscope optique ?',correction:'1. Colore le noyau en bleu\n2. Colore l\'amidon en violet-noir\n3. Trop petits (<0,2µm) → nécessite microscope électronique',notions:['Microscopie']},
      {id:'SV1-09',difficulte:2,titre:'Eucaryote vs procaryote',enonce:'1. 2 différences.\n2. Bactéries = ?\n3. Humains = ?',correction:'1. Eucaryote : noyau membranaire + organites. Procaryote : pas de noyau, ADN libre\n2. Procaryotes\n3. Eucaryotes',notions:['Eucaryote']},
      {id:'SV1-10',difficulte:2,titre:'Règles du schéma biologique',enonce:'Citer 4 règles essentielles d\'un bon schéma biologique.',correction:'1. Crayon à papier\n2. Traits de légende à la règle sans se croiser\n3. Légendes horizontales\n4. Titre + grandissement obligatoires',notions:['Schéma']},
      {id:'SV1-11',difficulte:2,titre:'Mitochondrie',enonce:'1. Que se passe-t-il dans la matrice ?\n2. Et sur les crêtes ?\n3. Pourquoi muscles = plus de mitochondries ?',correction:'1. Cycle de Krebs → CO₂ + NADH\n2. Chaîne respiratoire → ATP\n3. Besoin énergétique élevé lors de la contraction',notions:['Mitochondrie']},
      {id:'SV1-12',difficulte:2,titre:'Chloroplaste',enonce:'1. Structure.\n2. Lieu phase lumineuse.\n3. Lieu cycle de Calvin.',correction:'1. Double membrane + thylakoïdes (grana) dans le stroma\n2. Thylakoïdes → O₂ + ATP + NADPH\n3. Stroma → glucose',notions:['Chloroplaste']},
      {id:'SV1-13',difficulte:3,titre:'Taille des cellules',enonce:'GR 7µm · Bactérie 1µm · Noyau 5µm · Ribosome 25nm.\n1. Convertir en nm.\n2. Microscope pour ribosome.\n3. Classer.',correction:'1. GR=7000nm · Bactérie=1000nm · Noyau=5000nm · Ribosome=25nm\n2. Microscope électronique\n3. Ribosome < Bactérie < Noyau < GR',notions:['Taille']},
      {id:'SV1-14',difficulte:2,titre:'Paroi cellulosique',enonce:'1. Rôle.\n2. Pourquoi les cellules végétales n\'explosent pas dans l\'eau pure ?\n3. Que se passe-t-il en eau salée concentrée ?',correction:'1. Rigidité + protection\n2. La paroi résiste à la pression de turgescence\n3. Plasmolyse : eau sort → membrane se décolle de la paroi',notions:['Paroi']},
      {id:'SV1-15',difficulte:2,titre:'Vacuole centrale',enonce:'1. Que contient-elle ?\n2. Rôle dans la turgescence.\n3. Existe-t-elle dans les cellules animales ?',correction:'1. Eau + sels + sucres + pigments + déchets\n2. Pression contre la paroi → rigidité de la plante\n3. Petites vacuoles seulement (pas de grande vacuole centrale)',notions:['Vacuole']},
      {id:'SV1-16',difficulte:3,titre:'Totipotence',enonce:'1. Nom de la propriété permettant à une cellule végétale de régénérer une plante.\n2. Toutes les cellules ont-elles le même ADN ?\n3. Application pratique.',correction:'1. Totipotence\n2. Oui — même génome complet\n3. Micropropagation = clonage végétal',notions:['Totipotence']},
      {id:'SV1-17',difficulte:2,titre:'Réticulum endoplasmique',enonce:'1. Rôle du RER.\n2. Différence RE lisse.\n3. Lien avec Golgi.',correction:'1. Synthèse et transport des protéines (parsemé de ribosomes)\n2. RE lisse : sans ribosomes → lipides, détoxification\n3. Vésicules du RE → Golgi qui trie et modifie les protéines',notions:['Réticulum']},
      {id:'SV1-18',difficulte:3,titre:'Osmose',enonce:'Cellule végétale dans : eau pure · isotonique · hypertonique.\n1. Que se passe-t-il ?\n2. Définir osmose.\n3. Application médicale sérum physiologique.',correction:'1. Eau pure → turgescence · Isotonique → rien · Hypertonique → plasmolyse\n2. Mouvement eau à travers membrane semi-perméable vers milieu le plus concentré\n3. NaCl 9g/L ≈ isotonique au sang → pas de lyse lors des perfusions',notions:['Osmose']},
      {id:'SV1-19',difficulte:3,titre:'Cellule souche',enonce:'1. Définir.\n2. Embryonnaire vs adulte.\n3. Intérêt médical.',correction:'1. Cellule indifférenciée capable de s\'auto-renouveler et se différencier\n2. Embryonnaire = pluripotente (tous types). Adulte = multipotente\n3. Thérapie cellulaire : Parkinson, diabète type 1, brûlures',notions:['Cellule souche']},
      {id:'SV1-20',difficulte:3,titre:'Tableau comparatif cellules',enonce:'Compléter (✓/✗) : Paroi · Noyau · Mitochondrie · Chloroplaste · Vacuole centrale\npour : Cellule animale · Végétale · Bactérie',correction:'Paroi : ✗|✓(cellulose)|✓(peptidoglycane)\nNoyau : ✓|✓|✗(ADN libre)\nMitochondrie : ✓|✓|✗\nChloroplaste : ✗|✓|✗\nVacuole centrale : ✗|✓|✗',notions:['Bilan']},
    ]
  },
  {
    id:'metabolisme-seconde-svt', numero:2,
    titre:'Métabolisme — Respiration & Photosynthèse',
    sousTitre:'ATP · Respiration · Photosynthèse · Autotrophe · Hétérotrophe',
    icon:'⚡', color:'#10b981',
    notions:['Respiration cellulaire','Photosynthèse','ATP','Autotrophe','Hétérotrophe'],
    exercices:[
      {id:'SV2-01',difficulte:1,titre:'Équation respiration',enonce:'Écrire et équilibrer l\'équation bilan. Réactifs, produits, lieu.',correction:'C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ATP\nCytoplasme (glycolyse) + mitochondries (Krebs + chaîne)',notions:['Respiration']},
      {id:'SV2-02',difficulte:1,titre:'Équation photosynthèse',enonce:'Écrire l\'équation bilan. Réactifs, produits, lieu.',correction:'6CO₂ + 6H₂O + lumière → C₆H₁₂O₆ + 6O₂\nChloroplastes (thylakoïdes + stroma)',notions:['Photosynthèse']},
      {id:'SV2-03',difficulte:1,titre:'Autotrophe vs hétérotrophe',enonce:'1. Définir chacun.\n2. Classer : végétal vert · champignon · animal · cyanobactérie.\n3. Les humains ?',correction:'1. Autotrophe = fabrique sa matière. Hétérotrophe = consomme la matière d\'autres\n2. Autotrophes : végétal vert, cyanobactérie. Hétérotrophes : champignon, animal\n3. Hétérotrophes',notions:['Autotrophe']},
      {id:'SV2-04',difficulte:1,titre:'Rôle de l\'ATP',enonce:'1. Que signifie ATP ?\n2. Comment libère-t-il de l\'énergie ?\n3. 3 usages cellulaires.',correction:'1. Adénosine TriPhosphate\n2. ATP + H₂O → ADP + Pi + énergie (~30 kJ/mol)\n3. Contraction musculaire · synthèse protéines · transport actif',notions:['ATP']},
      {id:'SV2-05',difficulte:1,titre:'Bilan énergétique',enonce:'1. ATP par glucose (respiration).\n2. ATP par glucose (fermentation).\n3. Pourquoi les muscles préfèrent la respiration aérobie ?',correction:'1. 30-32 ATP\n2. 2 ATP\n3. 15-16× plus efficace → contraction prolongée',notions:['Bilan énergétique']},
      {id:'SV2-06',difficulte:2,titre:'Eau de chaux',enonce:'Air expiré barboté dans Ca(OH)₂.\n1. Observation.\n2. Équation.\n3. Conclusion.',correction:'1. Eau de chaux se trouble (CaCO₃ blanc)\n2. Ca(OH)₂ + CO₂ → CaCO₃↓ + H₂O\n3. Organisme produit CO₂ lors de la respiration cellulaire',notions:['CO₂']},
      {id:'SV2-07',difficulte:2,titre:'Facteurs limitants photosynthèse',enonce:'1. Effet d\'augmentation de lumière.\n2. Effet d\'augmentation CO₂.\n3. Loi de Liebig.',correction:'1. Photosynthèse augmente jusqu\'à saturation\n2. Augmentation → photosynthèse augmente\n3. La production est limitée par le facteur le moins disponible',notions:['Facteurs limitants']},
      {id:'SV2-08',difficulte:2,titre:'Deux phases de la photosynthèse',enonce:'1. Phase lumineuse vs cycle de Calvin.\n2. Lieu dans le chloroplaste.\n3. Produits de la phase lumineuse utilisés par Calvin.',correction:'1. Lumineuse : H₂O → O₂ + ATP + NADPH. Calvin : CO₂ → glucose\n2. Thylakoïdes / Stroma\n3. ATP et NADPH',notions:['Photosynthèse']},
      {id:'SV2-09',difficulte:2,titre:'Photolyse de l\'eau',enonce:'1. Définir photolyse.\n2. Équation simplifiée.\n3. D\'où vient l\'O₂ libéré ?',correction:'1. Dissociation de l\'eau par l\'énergie lumineuse\n2. 2H₂O + lumière → 4H⁺ + 4e⁻ + O₂\n3. De l\'eau (H₂O), prouvé par marquage ¹⁸O',notions:['Photolyse']},
      {id:'SV2-10',difficulte:2,titre:'Étapes respiration aérobie',enonce:'1. Nommer les 3 étapes.\n2. Lieu de la glycolyse.\n3. Devenir du pyruvate.',correction:'1. Glycolyse → Krebs → Chaîne respiratoire\n2. Cytoplasme (anaérobie)\n3. Mitochondrie → Acétyl-CoA → Krebs',notions:['Glycolyse']},
      {id:'SV2-11',difficulte:2,titre:'Fermentation',enonce:'1. Définir.\n2. Exemples levures.\n3. Dans les muscles.\n4. Équation fermentation lactique.',correction:'1. Dégradation anaérobie → 2 ATP seulement\n2. Alcoolique : glucose → éthanol + CO₂\n3. Lactique : effort intense → acide lactique → douleurs\n4. C₆H₁₂O₆ → 2 C₃H₆O₃ + 2 ATP',notions:['Fermentation']},
      {id:'SV2-12',difficulte:2,titre:'Tableau comparatif',enonce:'Compléter : Réactifs · Produits · Lieu · Qui · Énergie\npour Photosynthèse et Respiration.',correction:'Photo : CO₂+H₂O+lumière|Glucose+O₂|Chloroplastes|Autotrophes|Stocke\nRespi : Glucose+O₂|CO₂+H₂O+ATP|Cytoplasme+Mitochon.|Tous|Libère',notions:['Comparaison']},
      {id:'SV2-13',difficulte:2,titre:'Chlorophylle',enonce:'1. Longueurs d\'onde absorbées.\n2. Pourquoi plantes vertes.\n3. Deux types de chlorophylle.',correction:'1. Rouge (660-700 nm) et bleu (430-450 nm)\n2. Réfléchit le vert (550 nm)\n3. Chlorophylle a (bleu-vert) et b (vert-jaune)',notions:['Chlorophylle']},
      {id:'SV2-14',difficulte:3,titre:'Calcul photosynthèse',enonce:'Plante absorbe 6 mmol CO₂/h.\n1. mmol glucose produit/h.\n2. mmol O₂ libéré/h.\n3. Masse glucose en 8h. M=180.',correction:'1. 1 mmol glucose/h\n2. 6 mmol O₂/h\n3. 8 mmol × 180/1000 = 1,44 g',notions:['Calcul']},
      {id:'SV2-15',difficulte:2,titre:'Point de compensation',enonce:'1. Définir.\n2. En dessous.\n3. Au-dessus.',correction:'1. Intensité lumineuse où photosynthèse = respiration (bilan = 0)\n2. Respiration > photosynthèse → plante consomme ses réserves\n3. Photosynthèse > respiration → stockage → croissance',notions:['Point de compensation']},
      {id:'SV2-16',difficulte:2,titre:'Eau dans la plante',enonce:'1. L\'eau = réactif ou produit de la photosynthèse ?\n2. Et de la respiration ?\n3. Voie de l\'eau dans la plante.',correction:'1. Réactif (photolyse)\n2. Produit (chaîne respiratoire)\n3. Sol → racines → xylème → feuilles → stomates (transpiration)',notions:['Eau']},
      {id:'SV2-17',difficulte:3,titre:'Expérience d\'Engelmann',enonce:'Bactéries aérobies sur algue éclairée par spectre → s\'accumulent au rouge et bleu.\n1. Ce que cela démontre.\n2. Lien avec la chlorophylle.',correction:'1. Photosynthèse (production O₂) maximale dans le rouge et le bleu\n2. Ces longueurs d\'onde = spectre d\'absorption de la chlorophylle → elle capte la lumière',notions:['Spectre action']},
      {id:'SV2-18',difficulte:2,titre:'Matière organique',enonce:'1. Définir.\n2. Comment les plantes la fabriquent.\n3. Comment les animaux l\'obtiennent.',correction:'1. Molécules carbonées complexes : glucides, lipides, protéines, acides nucléiques\n2. Photosynthèse : CO₂ + H₂O + lumière → glucose\n3. Par l\'alimentation puis digestion',notions:['Matière organique']},
      {id:'SV2-19',difficulte:3,titre:'Cycle du carbone',enonce:'1. Rôle des plantes.\n2. Rôle des décomposeurs.\n3. Pourquoi forêts = puits de carbone.',correction:'1. Absorbent CO₂ → stockent C dans matière organique\n2. Dégradent matière morte → libèrent CO₂ + minéraux (recyclage)\n3. Absorbent plus de CO₂ qu\'elles n\'en libèrent → réduisent le CO₂ atmosphérique',notions:['Cycle carbone']},
      {id:'SV2-20',difficulte:3,titre:'Synthèse métabolisme',enonce:'Arbre en plein soleil vs champignon dans l\'obscurité.\n1. Processus métaboliques.\n2. Lequel produit le glucose.\n3. Que fait l\'arbre la nuit.',correction:'1. Arbre : photosynthèse + respiration. Champignon : respiration seule\n2. L\'arbre (photosynthèse)\n3. Respiration seule → consomme O₂ + libère CO₂',notions:['Bilan']},
    ]
  },
  {
    id:'biodiversite-seconde-svt', numero:3,
    titre:'Biodiversité & Évolution du vivant',
    sousTitre:'Espèce · Biodiversité · Sélection naturelle · Phylogénie · Fossiles',
    icon:'🌿', color:'#16a34a',
    notions:['Biodiversité','Espèce','Sélection naturelle','Fossile','Phylogénie'],
    exercices:[
      {id:'SV3-01',difficulte:1,titre:'3 niveaux de biodiversité',enonce:'1. Définir les 3 niveaux.\n2. Exemple pour chacun.\n3. Le moins connu.',correction:'1. Génétique (intra-espèce) · Spécifique (nb espèces) · Écosystèmes (milieux)\n2. Races de chiens · 300 espèces d\'arbres en forêt tropicale · forêt vs désert\n3. La diversité génétique',notions:['Biodiversité']},
      {id:'SV3-02',difficulte:1,titre:'Notion d\'espèce',enonce:'1. Définition biologique.\n2. Pourquoi cheval et âne = espèces différentes.\n3. Nomenclature binomiale.',correction:'1. Individus interféconds produisant descendance fertile\n2. Mulet stérile → pas de descendance fertile\n3. Genre espèce (Homo sapiens) — Linné 1758',notions:['Espèce']},
      {id:'SV3-03',difficulte:1,titre:'Sélection naturelle',enonce:'4 étapes. Exemple du papillon Biston betularia. Définir adaptation.',correction:'1. Variation · Hérédité · Compétition · Survie des + adaptés\n2. Avant industrie : blanc camouflé. Après : troncs noircis → forme noire sélectionnée\n3. Caractère héréditaire augmentant survie et reproduction',notions:['Sélection naturelle']},
      {id:'SV3-04',difficulte:1,titre:'Fossiles et évolution',enonce:'1. Définir fossile.\n2. Formation.\n3. Fossile stratigraphique.',correction:'1. Restes ou traces d\'organismes dans les roches sédimentaires\n2. Mort → enfouissement → minéralisation → compaction → roche\n3. Espèce à courte durée + large répartition → repère chronologique',notions:['Fossile']},
      {id:'SV3-05',difficulte:1,titre:'Arbre phylogénétique',enonce:'Humain · chimpanzé · gorille · orang-outan.\n1. Qu\'est-ce qu\'un nœud ?\n2. Humain et chimpanzé = nœud récent ?\n3. % ADN commun humain/chimpanzé.',correction:'1. Ancêtre commun\n2. Oui → plus proches parents\n3. 98,7%',notions:['Phylogénie']},
      {id:'SV3-06',difficulte:2,titre:'Chiffres de la biodiversité',enonce:'1. Espèces décrites vs estimées.\n2. Groupe le plus diversifié.\n3. Taux d\'extinction actuel vs naturel.',correction:'1. Décrites ~1,9 millions. Estimées ~8,7 millions\n2. Insectes (~1 million d\'espèces)\n3. 100-1000× supérieur → 6ème extinction de masse',notions:['Chiffres']},
      {id:'SV3-07',difficulte:2,titre:'Dérive génétique',enonce:'1. Définir.\n2. Dans quelle taille de population.\n3. Exemple effet fondateur.',correction:'1. Variation aléatoire des fréquences alléliques par hasard\n2. Plus petite population → dérive plus forte\n3. Amish : polydactylie sur-représentée (fondateurs porteurs)',notions:['Dérive génétique']},
      {id:'SV3-08',difficulte:2,titre:'Preuves de l\'évolution',enonce:'Citer et expliquer 4 preuves de l\'évolution commune.',correction:'1. Fossiles (formes intermédiaires)\n2. Anatomie comparée (organes homologues : aile chauve-souris = main humaine)\n3. ADN universel + gènes homologues\n4. Embryologie comparée (embryons vertébrés similaires)',notions:['Preuves']},
      {id:'SV3-09',difficulte:2,titre:'Organes vestigiaux',enonce:'1. Définir.\n2. Deux exemples chez l\'humain.\n3. Ce qu\'ils prouvent.',correction:'1. Organe réduit, non fonctionnel, vestige d\'un ancêtre\n2. Appendice · coccyx (vestige de queue)\n3. Descente d\'ancêtres qui utilisaient ces organes → évolution',notions:['Organes vestigiaux']},
      {id:'SV3-10',difficulte:2,titre:'Sélection naturelle vs artificielle',enonce:'1. Différence.\n2. Exemple sélection artificielle.\n3. Qui a inspiré Darwin.',correction:'1. Naturelle : environnement. Artificielle : l\'humain choisit\n2. Races de chiens (toutes du loup) · maïs du téosinte\n3. Éleveurs de pigeons anglais',notions:['Sélection']},
      {id:'SV3-11',difficulte:2,titre:'Classification du vivant',enonce:'Classer l\'humain (6 niveaux). Nom scientifique.',correction:'Animalia → Chordata → Mammalia → Primates → Hominidae → Homo sapiens',notions:['Classification']},
      {id:'SV3-12',difficulte:2,titre:'Biodiversité et stabilité des écosystèmes',enonce:'1. Définir écosystème.\n2. Pourquoi biodiversité = stabilité.\n3. Extinction en cascade.',correction:'1. Êtres vivants (biocénose) + milieu (biotope)\n2. Redondance fonctionnelle → résistance aux perturbations\n3. Loups Yellowstone disparus → cerfs prolifèrent → surpâturage → érosion berges → poissons disparaissent',notions:['Écosystème']},
      {id:'SV3-13',difficulte:2,titre:'Mutation et biodiversité',enonce:'1. Définir mutation.\n2. Rôle dans l\'évolution.\n3. Exemple de mutation bénéfique.',correction:'1. Modification aléatoire de la séquence ADN\n2. Source de nouveaux allèles → variabilité → matière première sélection naturelle\n3. Résistance paludisme chez porteurs HbA/HbS',notions:['Mutation']},
      {id:'SV3-14',difficulte:2,titre:'Évolution humaine',enonce:'1. Depuis quand Homo sapiens.\n2. Qui est Lucy.\n3. Ancêtre commun humain-chimpanzé.',correction:'1. ~300 000 ans (Jebel Irhoud, Maroc)\n2. Australopithecus afarensis (3,2 Ma), bipède\n3. ~6-8 millions d\'années',notions:['Évolution humaine']},
      {id:'SV3-15',difficulte:3,titre:'Fréquences alléliques',enonce:'100 individus : 36 AA · 48 Aa · 16 aa.\n1. Fréquences p(A) et q(a).\n2. Vérifier p+q=1.',correction:'p(A) = (72+48)/200 = 0,60\nq(a) = (32+48)/200 = 0,40\np+q = 1 ✓',notions:['Fréquences alléliques']},
      {id:'SV3-16',difficulte:2,titre:'Menaces sur la biodiversité',enonce:'5 grandes menaces IPBES 2019. En expliquer 2.',correction:'1. Changement utilisation terres 2. Surexploitation 3. Changement climatique 4. Pollution 5. Espèces invasives\nDéforestation : destruction habitats → perte espèces\nEspèces invasives : compétition avec espèces locales',notions:['Menaces']},
      {id:'SV3-17',difficulte:2,titre:'Espèce clé de voûte',enonce:'Loutre → oursins → algues kelp.\n1. Définir.\n2. Disparition des loutres.\n3. Outil de conservation.',correction:'1. Espèce dont la disparition a des effets disproportionnés sur l\'écosystème\n2. Oursins prolifèrent → kelp détruit → perte nombreuses espèces\n3. Cibler protection des espèces clés dans les aires protégées',notions:['Espèce clé']},
      {id:'SV3-18',difficulte:3,titre:'Convergence évolutive',enonce:'Dauphin et requin : forme fusiforme similaire.\n1. Définir convergence évolutive.\n2. Prouve ancêtre commun récent ?\n3. Autre exemple.',correction:'1. Espèces non apparentées développant caractères similaires sous même pression sélective\n2. Non → même milieu → même adaptation (pas d\'ancêtre commun récent)\n3. Ailes chauve-souris/oiseau/ptérosaure · yeux pieuvre/vertébrés',notions:['Convergence']},
      {id:'SV3-19',difficulte:3,titre:'Extinction de masse',enonce:'1. La plus récente ? Quand ? Cause.\n2. % espèces disparues.\n3. La 6ème extinction.',correction:'1. KPg (66 Ma) → impact météoritique Chicxulub → dinosaures non aviens\n2. ~75% des espèces\n3. En cours (Anthropocène) → 100-1000× taux naturel → activité humaine',notions:['Extinction']},
      {id:'SV3-20',difficulte:3,titre:'Bilan évolution',enonce:'1. Lien mutation-sélection-biodiversité.\n2. Pourquoi évolution "opportuniste".\n3. Biodiversité actuelle = il y a 100 Ma ?',correction:'1. Mutations → allèles → sélection trie → adaptations → diversification\n2. Pas de direction ni projet → agit sur ce qui existe\n3. Non : dinosaures disparus → radiation mammifères → biodiversité actuelle = 4 Ga d\'évolution',notions:['Bilan']},
    ]
  },
  {
    id:'communication-seconde-svt', numero:4,
    titre:'Communication & Sélection sexuelle',
    sousTitre:'Phéromones · Signaux · Sélection sexuelle · Dimorphisme',
    icon:'🦚', color:'#84cc16',
    notions:['Phéromones','Sélection sexuelle','Communication animale'],
    exercices:[
      {id:'SV4-01',difficulte:1,titre:'Types de signaux',enonce:'1. 3 types de signaux.\n2. Exemple pour chacun.\n3. Communication intraspécifique.',correction:'1. Chimique · Sonore · Visuel\n2. Phéromones · chant oiseaux · queue du paon\n3. Entre individus de la même espèce',notions:['Communication']},
      {id:'SV4-02',difficulte:1,titre:'Phéromones',enonce:'1. Définir.\n2. Comment détectées.\n3. Bombyx mori.',correction:'1. Molécule chimique émise déclenchant une réponse chez un congénère\n2. Olfaction (antennes insectes)\n3. Femelle émet bombycol → mâle détecte à 10 km',notions:['Phéromones']},
      {id:'SV4-03',difficulte:1,titre:'Sélection sexuelle',enonce:'1. Définir.\n2. Compétition intra vs intersexuelle.\n3. Exemple pour chacun.',correction:'1. Sélection liée au choix du partenaire reproducteur\n2. Intra : combats entre mâles. Inter : un sexe choisit l\'autre selon critères\n3. Cerfs (bois) · femelle paon qui choisit',notions:['Sélection sexuelle']},
      {id:'SV4-04',difficulte:1,titre:'Chant des oiseaux',enonce:'1. Fonctions du chant.\n2. Pourquoi rossignol chante la nuit.\n3. Lien sélection sexuelle.',correction:'1. Délimitation territoire + attraction femelles\n2. Moins de bruit → signal porte plus loin\n3. Femelles choisissent meilleurs chanteurs → sélection intersexuelle',notions:['Communication sonore']},
      {id:'SV4-05',difficulte:1,titre:'Bioluminescence',enonce:'1. Définir.\n2. Réaction chimique.\n3. Exemple marin.',correction:'1. Production de lumière par un organisme vivant\n2. Luciférine + O₂ + ATP → lumière (luciférase)\n3. Méduses · baudroie · calmars',notions:['Bioluminescence']},
      {id:'SV4-06',difficulte:2,titre:'Paradoxe de Zahavi',enonce:'Queue du paon = signal honnête.\n1. Pourquoi c\'est un handicap.\n2. Pourquoi femelles préfèrent plus d\'ocelles.\n3. Ce que révèle ce signal.',correction:'1. Longue queue = coûteuse (poids, visible des prédateurs)\n2. Survivre malgré le handicap → robustesse génétique\n3. Signal honnête = révèle qualité génétique réelle',notions:['Handicap']},
      {id:'SV4-07',difficulte:2,titre:'Phéromones d\'alarme',enonce:'Pucerons : phéromone d\'alarme → fuite.\n1. Avantage évolutif.\n2. Qui émet ? Quand.\n3. Pourquoi colonies clonales.',correction:'1. Avertit la colonie → évite prédation collective\n2. Puceron attaqué par prédateur\n3. Parthénogenèse → individus génétiquement identiques',notions:['Alarme']},
      {id:'SV4-08',difficulte:2,titre:'Territoire et communication',enonce:'Loups marquent leur territoire.\n1. Signaux utilisés.\n2. Fonction du territoire.\n3. Lien avec reproduction.',correction:'1. Urine (chimique) · hurlements (sonore) · postures (visuel)\n2. Ressources + reproduction + protection\n3. Couple alpha se reproduit → territoire assure les ressources',notions:['Territoire']},
      {id:'SV4-09',difficulte:2,titre:'Dimorphisme sexuel',enonce:'1. Définir.\n2. 3 exemples.\n3. Lien sélection sexuelle.',correction:'1. Différence de morphologie mâle/femelle de même espèce\n2. Paon (queue) · cerf (bois) · mandrill (couleurs)\n3. Résulte de la sélection sexuelle : caractères amplifiés génération après génération',notions:['Dimorphisme']},
      {id:'SV4-10',difficulte:2,titre:'Comportements ritualisés',enonce:'1. Définir.\n2. Avantage pour reproduction.\n3. Exemple grèbes huppés.',correction:'1. Séquence comportementale stéréotypée, héréditaire\n2. Reconnaissance espèce + évaluation partenaire + synchronisation\n3. Danse en miroir sur l\'eau + offrande de végétaux',notions:['Comportement ritualisé']},
      {id:'SV4-11',difficulte:2,titre:'Danse des abeilles',enonce:'1. Qui a découvert ?\n2. Décrire la danse en 8.\n3. Direction et distance.',correction:'1. Karl von Frisch (1946), Prix Nobel 1973\n2. Abdomen agité en trajet en 8\n3. Angle verticale = direction du soleil. Durée = distance',notions:['Danse abeilles']},
      {id:'SV4-12',difficulte:2,titre:'Signaux chimiques vs visuels',enonce:'Avantages et inconvénients de chaque type.',correction:'Chimiques : + longue portée · nuit/jour · persiste. − lent · impacté par vent\nVisuels : + rapide · précis · directionnel. − requiert vision · jour seulement',notions:['Comparaison']},
      {id:'SV4-13',difficulte:2,titre:'Aposématisme',enonce:'Dendrobate rouge vif.\n1. Intra ou interspécifique ?\n2. Définir aposématisme.\n3. Mimétisme batésien.',correction:'1. Interspécifique (signal aux prédateurs)\n2. Coloration vive signalant la toxicité\n3. Espèce inoffensive copie la couleur d\'une espèce toxique',notions:['Aposématisme']},
      {id:'SV4-14',difficulte:3,titre:'Comportement coopératif',enonce:'Lions chassent en groupe.\n1. Avantage.\n2. Explication sélection naturelle.\n3. Altruisme kin-sélection.',correction:'1. Proies plus grosses · taux de réussite élevé · défense\n2. Coopérants → plus de nourriture → meilleure survie reproduction\n3. Aide aux apparentés → transmission de ses gènes via les proches',notions:['Coopération']},
      {id:'SV4-15',difficulte:2,titre:'Investissement parental',enonce:'1. Définir.\n2. Quel sexe investit plus ? Pourquoi.\n3. Lien sélection sexuelle.',correction:'1. Effort consacré aux soins des descendants\n2. Femelles généralement (gestation, allaitement) → gamètes plus coûteux\n3. Sexe qui investit moins est en compétition → sélection sexuelle',notions:['Investissement parental']},
      {id:'SV4-16',difficulte:3,titre:'Empreinte (imprinting)',enonce:'Caneton suit le premier objet en mouvement.\n1. Nom du phénomène.\n2. Qui l\'a décrit.\n3. Inné ou acquis.',correction:'1. Empreinte (imprinting)\n2. Konrad Lorenz (1937), Prix Nobel 1973\n3. À la frontière inné/acquis',notions:['Empreinte']},
      {id:'SV4-17',difficulte:2,titre:'Cétacés et ultrasons',enonce:'1. Pourquoi sons bien propagés dans l\'eau.\n2. Écholocation.\n3. Autre usage.',correction:'1. Eau plus dense → son 4× plus rapide, longues distances\n2. Clicks → écho → image acoustique de l\'environnement\n3. Chasse · navigation · évitement obstacles',notions:['Écholocation']},
      {id:'SV4-18',difficulte:2,titre:'Reconnaissance individuelle',enonce:'Pingouins retrouvent leur poussin.\n1. Signal utilisé.\n2. Avantage évolutif.\n3. Autre exemple.',correction:'1. Cri individuel unique (sonore)\n2. Nourrir son propre poussin → transmission de ses gènes\n3. Dauphins (sifflets signatures) · éléphants (odeur)',notions:['Reconnaissance']},
      {id:'SV4-19',difficulte:3,titre:'Évolution de la communication',enonce:'1. Pourquoi espèces nocturnes = peu de signaux visuels.\n2. Signaux varient selon habitats.\n3. Exemple adaptation signal au milieu.',correction:'1. Vision limitée la nuit → signaux chimiques et sonores\n2. Forêt : basses fréquences portent mieux. Prairie : visuel (longue portée)\n3. Merle urbain chante plus aigu pour dépasser le bruit de fond',notions:['Évolution communication']},
      {id:'SV4-20',difficulte:3,titre:'Bilan communication',enonce:'Paon parade en clairière ensoleillée.\n1. Type signal et sélection.\n2. Avantage adaptif nombreux ocelles.\n3. Si forêts plus denses ?',correction:'1. Visuel → sélection intersexuelle\n2. Bonne santé + gènes de qualité → sélection renforce le caractère\n3. Parade visuelle moins efficace → pression vers signaux sonores/chimiques',notions:['Bilan']},
    ]
  },
  {
    id:'geosciences-seconde-svt', numero:5,
    titre:'Géosciences — Formation des paysages',
    sousTitre:'Érosion · Sédimentation · Roches · Stratigraphie · Cartes géologiques',
    icon:'🏔️', color:'#f59e0b',
    notions:['Érosion','Sédimentation','Roches','Principe superposition'],
    exercices:[
      {id:'SV5-01',difficulte:1,titre:'3 étapes formation paysage sédimentaire',enonce:'Décrire les 3 étapes. Zones géographiques ?',correction:'1. Altération : dégradation des roches\n2. Transport : eau · vent · glace · gravité\n3. Sédimentation : dépôt dans bassins\nLieux : altitude → versants → plaines/bassins',notions:['Érosion','Sédimentation']},
      {id:'SV5-02',difficulte:1,titre:'Altération mécanique vs chimique',enonce:'1. Mécanique + 2 exemples.\n2. Chimique + 2 exemples.\n3. Indépendants ?',correction:'1. Mécanique : fragmentation. Ex : gélifraction · racines\n2. Chimique : transformation. Ex : dissolution calcaire · oxydation fer\n3. Complémentaires : mécanique augmente surface → accélère chimique',notions:['Altération']},
      {id:'SV5-03',difficulte:1,titre:'Principe de superposition',enonce:'Coupe bas→haut : granite / calcaire / grès / argile.\n1. Principe utilisé.\n2. Classer.\n3. Si couches renversées.',correction:'1. Principe de superposition\n2. Granite → calcaire → grès → argile (du + ancien au + récent)\n3. Ne s\'applique plus → chercher indices de retournement',notions:['Stratigraphie']},
      {id:'SV5-04',difficulte:1,titre:'3 familles de roches',enonce:'Définir + 2 exemples chacune. La plus courante ?',correction:'1. Sédimentaires : dépôt. Ex : calcaire, grès\n2. Magmatiques : magma. Ex : granite, basalte\n3. Métamorphiques : pression/T°. Ex : marbre, ardoise\nLa + courante : sédimentaires (75% surface terrestre)',notions:['Types roches']},
      {id:'SV5-05',difficulte:1,titre:'Agents d\'érosion',enonce:'4 agents + relief caractéristique créé.',correction:'1. Eau/rivières → gorges, méandres, deltas\n2. Vent → dunes, yardangs\n3. Glaciers → vallées en U, moraines\n4. Mer → falaises, arches',notions:['Agents érosion']},
      {id:'SV5-06',difficulte:2,titre:'Formation du calcaire',enonce:'1. Composition.\n2. Formation.\n3. Paysages karstiques.',correction:'1. CaCO₃ (calcite + coquilles d\'organismes)\n2. Dépôt marin de coquilles → compaction + cimentation\n3. H₂CO₃ dissout CaCO₃ → grottes, gouffres, lapiés',notions:['Calcaire','Karst']},
      {id:'SV5-07',difficulte:2,titre:'Cycle sédimentaire',enonce:'Du granite en montagne à la roche sédimentaire.',correction:'1. Altération granite → sables + argiles\n2. Transport par rivières\n3. Dépôt lac/mer → compaction + cimentation\n4. Grès (sable) ou argile (particules fines)\n5. Uplift → érosion → nouveau cycle',notions:['Cycle sédimentaire']},
      {id:'SV5-08',difficulte:2,titre:'Lecture carte géologique',enonce:'1. Que représentent les couleurs.\n2. Les lignes entre zones.\n3. Le pendage.',correction:'1. Types de roches (légende)\n2. Contact géologique (faille, discordance)\n3. Tiret + flèche + angle (direction et inclinaison)',notions:['Carte géologique']},
      {id:'SV5-09',difficulte:2,titre:'Delta et alluvions',enonce:'1. Définir un delta.\n2. Pourquoi se forme-t-il.\n3. Deux exemples mondiaux.',correction:'1. Dépôt sédimentaire triangulaire à l\'embouchure d\'un fleuve\n2. Vitesse chute → transport insuffisant → dépôt\n3. Nil · Gange-Brahmapoutre · Mississippi',notions:['Delta']},
      {id:'SV5-10',difficulte:2,titre:'Grottes et spéléothèmes',enonce:'1. Formation des grottes.\n2. Stalactite vs stalagmite.\n3. Information climatique.',correction:'1. H₂CO₃ dissout CaCO₃ → galeries karstiques\n2. Stalactite : descend du plafond. Stalagmite : monte du sol\n3. Couches de croissance → δ¹⁸O → températures et précipitations passées',notions:['Karst']},
      {id:'SV5-11',difficulte:2,titre:'Falaise et érosion côtière',enonce:'Falaises de craie : ~30 cm/an.\n1. Agents.\n2. Devenir des matériaux.\n3. Impact humain.',correction:'1. Vagues + dissolution + vent + gel/dégel\n2. Blocs → galets → sable → transportés par courants\n3. Constructions (surcharge) · imperméabilisation · barrages (baisse apports sédimentaires)',notions:['Érosion côtière']},
      {id:'SV5-12',difficulte:2,titre:'Stratigraphie — datation relative',enonce:'Coupe : limestone / granite intrusif / grès / basalte (recoupe grès).\n1. Plus ancien et récent.\n2. Principes.\n3. Ammonites dans limestone.',correction:'1. Plus ancien : limestone. Plus récent : basalte\n2. Granite : recoupement. Basalte : recoupement\n3. Fossile stratigraphique Mésozoïque → limestone date du Mésozoïque',notions:['Datation relative']},
      {id:'SV5-13',difficulte:2,titre:'Sols',enonce:'1. Définir sol.\n2. Les 3 horizons.\n3. Temps formation 1 cm.',correction:'1. Interface roche-mère/atmosphère (altération physico-chimique + biologique)\n2. A (humus) · B (argiles, oxydes) · C (roche altérée)\n3. 100 à 1000 ans → ressource non renouvelable',notions:['Sol']},
      {id:'SV5-14',difficulte:3,titre:'Vitesse de sédimentation',enonce:'Carotte 3 m formée en 300 000 ans.\n1. Vitesse en mm/an.\n2. Fossile à 1,5 m → âge.\n3. Comparer avec formation sols.',correction:'1. 3 m / 300 000 ans = 0,01 mm/an\n2. 150 000 ans\n3. Sol : 0,01-0,1 mm/an → comparable, tous extrêmement lents',notions:['Calcul']},
      {id:'SV5-15',difficulte:2,titre:'Impact humain sur l\'érosion',enonce:'Déforestation ×10-100 l\'érosion.\n1. Explication.\n2. Autres activités.\n3. Mesures pour limiter.',correction:'1. Racines retiennent le sol → sans arbres : ruissellement intense\n2. Agriculture intensive · surpâturage · urbanisation · mines\n3. Labours isohypses · CIPAN · haies · semis direct',notions:['Impact humain']},
      {id:'SV5-16',difficulte:2,titre:'Glacier et moraine',enonce:'1. Définir glacier + zones.\n2. Moraine.\n3. Information sur les glaciations.',correction:'1. Masse de glace. Zone accumulation + zone ablation\n2. Dépôts transportés par le glacier\n3. Moraines frontales = limite maximale → reconstituent les glaciations',notions:['Glacier']},
      {id:'SV5-17',difficulte:2,titre:'Relief et dureté des roches',enonce:'Granite en relief vs sédimentaires en creux.\n1. Expliquer.\n2. Exemple montagne granitique.',correction:'1. Granite = très dur → résiste érosion → relief. Sédimentaires tendres → dépression\n2. Mont Blanc · Aiguilles Rouges',notions:['Relief']},
      {id:'SV5-18',difficulte:3,titre:'Dissolution du gypse',enonce:'CaSO₄·2H₂O soluble dans l\'eau.\n1. Conséquences paysage.\n2. Risques constructions.\n3. Région française.',correction:'1. Dissolution → cavités → effondrements · dolines\n2. Fondations instables · fissures · effondrements brutaux\n3. Val-d\'Oise · Jura · Causses',notions:['Dissolution']},
      {id:'SV5-19',difficulte:3,titre:'Foraminifères et paléoclimats',enonce:'1. Définir foraminifère.\n2. Indicateur chimique utilisé.\n3. δ¹⁸O bas = ?',correction:'1. Protiste marin à coquille CaCO₃ → fossile dans sédiments marins\n2. Rapport isotopique δ¹⁸O dans les coquilles\n3. δ¹⁸O bas → période GLACIAIRE froide (¹⁸O reste dans les glaces)',notions:['Paléoclimats']},
      {id:'SV5-20',difficulte:3,titre:'Du récif au sommet alpin',enonce:'En 100 Ma, un récif corallien peut devenir une montagne calcaire. Décrire.',correction:'1. Récif corallien (Jurassique) → accumulation coquilles\n2. Compaction + cimentation → calcaire\n3. Collision continentale (Alpes) → soulèvement → calcaire en altitude\n4. Érosion → transport → dépôt → nouveau cycle',notions:['Dynamique terrestre']},
    ]
  },
  {
    id:'erosion-humaine-seconde-svt', numero:6,
    titre:'Érosion & Activité humaine',
    sousTitre:'Déforestation · Agriculture · Urbanisation · Risques · Développement durable',
    icon:'🏭', color:'#f97316',
    notions:['Déforestation','Impact humain','Risques naturels','Développement durable'],
    exercices:[
      {id:'SV6-01',difficulte:1,titre:'Impact de la déforestation',enonce:'1. Définir.\n2. 3 conséquences sur l\'érosion.\n3. Données mondiales.',correction:'1. Destruction permanente des forêts\n2. Perte racines · ruissellement ×10-100 · désertification\n3. ~10-15 millions ha/an (Amazonie, Bornéo, Congo)',notions:['Déforestation']},
      {id:'SV6-02',difficulte:1,titre:'Agriculture intensive et sols',enonce:'1. Définir.\n2. 3 effets négatifs.\n3. Érosion hydrique agricole.',correction:'1. Maximise rendements (mécanisation, engrais, monocultures)\n2. Tassement · perte humus · pollution nitrates\n3. Pluie sur sols nus emporte particules fines → perte irréversible de sol',notions:['Agriculture intensive']},
      {id:'SV6-03',difficulte:1,titre:'Urbanisation et imperméabilisation',enonce:'1. Définir imperméabilisation.\n2. Conséquences sur cycle de l\'eau.\n3. Données France.',correction:'1. Recouvrement par surfaces imperméables (béton, asphalte)\n2. Ruissellement rapide → crues urbaines · moins de recharge nappes\n3. ~20 000-30 000 ha/an en France',notions:['Imperméabilisation']},
      {id:'SV6-04',difficulte:1,titre:'Risques naturels aggravés',enonce:'4 risques aggravés par l\'activité humaine.',correction:'1. Inondations : imperméabilisation + déforestation\n2. Glissements : végétation absente\n3. Coulées de boue : argile + eau + pente\n4. Érosion côtière : constructions + tempêtes',notions:['Risques']},
      {id:'SV6-05',difficulte:2,titre:'Plan de Prévention des Risques',enonce:'1. Qu\'est-ce qu\'un PPR.\n2. Qui l\'élabore.\n3. 3 zones et couleurs.',correction:'1. Document cartographiant zones à risque + règles de construction\n2. L\'État (préfet) + communes\n3. Rouge : inconstructible · Bleu : sous conditions · Blanc : sans restriction',notions:['PPR']},
      {id:'SV6-06',difficulte:2,titre:'Haie bocagère',enonce:'1. Rôle anti-érosif.\n2. Conséquences arrachage.\n3. Pourquoi replanter.',correction:'1. Ralentit ruissellement · retient sédiments · brise-vent\n2. Ruissellement ×3-10 · érosion · perte biodiversité\n3. Cycle eau · CO₂ · biodiversité pollinisateurs · élevage',notions:['Haies bocagères']},
      {id:'SV6-07',difficulte:2,titre:'Nitrates et pollution des eaux',enonce:'1. Comment nitrates atteignent les nappes.\n2. Risques sanitaires.\n3. Eutrophisation.',correction:'1. Engrais → nitrates solubles → percolation → nappe\n2. Méthémoglobinémie nourrissons · cancers digestifs\n3. Nitrates + phosphates → algues → O₂ consommé → mort poissons',notions:['Nitrates']},
      {id:'SV6-08',difficulte:2,titre:'Agriculture durable',enonce:'4 pratiques limitant l\'érosion.',correction:'1. Labour selon isohypses\n2. CIPAN (sol jamais nu)\n3. Agroforesterie\n4. Semis direct (no-till)',notions:['Agriculture durable']},
      {id:'SV6-09',difficulte:2,titre:'Avalanches',enonce:'1. Déclenchement.\n2. Rôle des forêts en altitude.\n3. Infrastructures.',correction:'1. Neige instable (surcharge + couche fragile) → rupture d\'équilibre\n2. Ancrent la neige + brise-vent. Déforestation → risque ×3-5\n3. Filets paravalanches · merlons · déclenchement préventif explosifs',notions:['Avalanche']},
      {id:'SV6-10',difficulte:2,titre:'Érosion côtière — falaises',enonce:'Recul 20-40 cm/an.\n1. Causes naturelles et anthropiques.\n2. Conséquences.\n3. Solutions.',correction:'1. Naturelles : vagues + gel/dégel. Anthropiques : constructions + barrages\n2. Maisons menacées · routes coupées · patrimoine détruit\n3. Enrochements · recul stratégique · suivi LiDAR/drones',notions:['Érosion côtière']},
      {id:'SV6-11',difficulte:2,titre:'Désertification',enonce:'1. Définir.\n2. Zones concernées.\n3. Causes humaines et naturelles.',correction:'1. Dégradation terres arides → perte productivité → avancée du désert\n2. Sahel · Méditerranée · Asie centrale\n3. Naturelles : sécheresses. Humaines : surpâturage · déforestation',notions:['Désertification']},
      {id:'SV6-12',difficulte:2,titre:'Bioremédiation',enonce:'1. Définir.\n2. Phytoremédiation.\n3. Micro-organismes.',correction:'1. Organismes vivants pour dépolluer sols/eaux\n2. Thlaspi accumule zinc/cadmium. Tournesols (Tchernobyl)\n3. Alcanivorax dégradent hydrocarbures (marées noires)',notions:['Bioremédiation']},
      {id:'SV6-13',difficulte:3,titre:'Inondations et artificialisation',enonce:'40% d\'un bassin artificialisé.\n1. Coefficient de ruissellement.\n2. Comparer avec forêt.\n3. Mesures en ville.',correction:'1. Cr ≈ 40%×0,90 + 60%×0,15 = 45%\n2. Forêt Cr ≈ 5-15% → ruissellement 3-9× moins fort\n3. Jardins de pluie · toitures végétalisées · parkings perméables · bassins rétention',notions:['Ruissellement']},
      {id:'SV6-14',difficulte:2,titre:'Glaciers en recul',enonce:'Glacier du Rhône : −3 km depuis 1870.\n1. Cause principale.\n2. Conséquences sur ressources en eau.\n3. Risques.',correction:'1. Réchauffement climatique → fonte > accumulation\n2. Court terme : + eau. Long terme : raréfaction en été\n3. Lacs glaciaires instables · parois déstabilisées',notions:['Glaciers']},
      {id:'SV6-15',difficulte:2,titre:'Digues et littoral',enonce:'1. Rôle d\'une digue.\n2. Effets pervers sur érosion.\n3. Recul stratégique.',correction:'1. Protection contre vagues et submersion\n2. Pied de digue érodé · starvation sédimentaire · fausse sécurité\n3. Décision de ne pas protéger certaines zones et d\'interdire nouvelles constructions',notions:['Gestion littorale']},
      {id:'SV6-16',difficulte:3,titre:'Calcul perte de sol',enonce:'8 t/ha/an perdues. En 50 ans, épaisseur perdue ? (densité=1,2 t/m³). Durabilité ?',correction:'Masse 50 ans = 400 t/ha = 333 m³/ha / 10000m² = 3,3 cm\nFormation sol : 1cm/100-1000 ans → 3,3 cm nécessite 330-3300 ans\nInsoutenable → perte irréversible',notions:['Calcul']},
      {id:'SV6-17',difficulte:2,titre:'Submersion marine',enonce:'Tempête Xynthia (2010).\n1. Définir submersion.\n2. Pourquoi risque augmente avec réchauffement.\n3. Mesures.',correction:'1. Zones côtières envahies par la mer lors de tempêtes\n2. Montée du niveau marin + tempêtes plus intenses\n3. Digues · alerte précoce · PPRL · recul stratégique',notions:['Submersion']},
      {id:'SV6-18',difficulte:2,titre:'Compostage',enonce:'1. Définir.\n2. Bénéfice pour les sols.\n3. Comparer avec engrais chimiques.',correction:'1. Décomposition aérobie contrôlée → humus stable\n2. Structure du sol · biodiversité · libération lente nutriments\n3. Compost : lent · structure · pas pollution. Chimique : rapide · précis · pollue nitrates',notions:['Compostage']},
      {id:'SV6-19',difficulte:3,titre:'Grande Muraille Verte',enonce:'Initiative africaine Sahel.\n1. Pays et longueur.\n2. Mécanismes biologiques.\n3. Défis.',correction:'1. 11 pays Union Africaine (2007) · 8000 km\n2. Racines retiennent sol · matière organique · humidité · brise-vent\n3. Faible taux survie plantations · financement insuffisant',notions:['Reboisement']},
      {id:'SV6-20',difficulte:3,titre:'Bilan impact humain',enonce:'1. Érosion naturelle vs anthropique.\n2. Humain = agent géologique majeur ?\n3. Anthropocène.',correction:'1. Naturel : 0,1-1 mm/an. Agriculture intensive : ×10-100\n2. Oui : déplace ~50 Gt sédiments/an vs fleuves 20 Gt/an\n3. Nouvelle époque géologique définie par l\'impact humain sur la Terre',notions:['Anthropocène']},
    ]
  },
  {
    id:'agrosystemes-seconde-svt', numero:7,
    titre:'Agrosystèmes & Développement durable',
    sousTitre:'Agrosystème · Biomasse · Engrais · Fertilité · Agroécologie',
    icon:'🌾', color:'#a16207',
    notions:['Agrosystème','Biomasse','Engrais','Fertilité','Agroécologie'],
    exercices:[
      {id:'SV7-01',difficulte:1,titre:'Agrosystème vs écosystème naturel',enonce:'Compléter : Biodiversité · Cycle nutriments · Énergie · Stabilité',correction:'Biodiversité : élevée | faible (monoculture)\nCycle nutriments : bouclé | ouvert (export récoltes)\nÉnergie : soleil seul | soleil + fossile\nStabilité : haute | faible',notions:['Agrosystème']},
      {id:'SV7-02',difficulte:1,titre:'La biomasse',enonce:'1. Définir.\n2. Aérienne vs racinaire.\n3. Production primaire nette.',correction:'1. Ensemble de la matière organique produite par les vivants\n2. Aérienne : tiges, feuilles, fruits. Racinaire : racines\n3. PPN = photosynthèse totale − respiration',notions:['Biomasse']},
      {id:'SV7-03',difficulte:1,titre:'Éléments nutritifs des plantes',enonce:'1. Rôles de N, P, K.\n2. Rôle du Mg.\n3. Symptôme carence azote.',correction:'1. N : chlorophylle + protéines. P : racines + ADN. K : résistance + qualité fruits\n2. Mg : constituant de la chlorophylle\n3. Chlorose (feuilles jaunes) + croissance réduite',notions:['Nutriments']},
      {id:'SV7-04',difficulte:1,titre:'Types d\'engrais',enonce:'1. Organiques vs minéraux.\n2. Avantages de chacun.\n3. Engrais NPK.',correction:'1. Organiques : compost, fumier. Minéraux : urée, superphosphate\n2. Organiques : structure + biodiversité. Minéraux : rapide + précis\n3. Ternaire N+P₂O₅+K₂O',notions:['Engrais']},
      {id:'SV7-05',difficulte:1,titre:'Rotation des cultures',enonce:'1. Définir.\n2. Légumineuse après céréale.\n3. CIPAN.',correction:'1. Alternance de cultures différentes\n2. Légumineuses fixent N₂ (Rhizobium) → enrichissent le sol\n3. Culture piège à nitrates → protège sol entre cultures',notions:['Rotation']},
      {id:'SV7-06',difficulte:2,titre:'Bilan des flux agrosystème',enonce:'10 ha blé : 75 t grain + 90 t paille.\n1. Ce qui sort / entre.\n2. Pourquoi engrais.\n3. Laisser la paille ?',correction:'1. Sort : grain + paille. Entre : engrais + semences + énergie\n2. Export emporte N, P, K → sol s\'appauvrit\n3. Restitution matière organique + K → améliore structure',notions:['Flux']},
      {id:'SV7-07',difficulte:2,titre:'Fixation biologique de l\'azote',enonce:'1. Définir FBN.\n2. Bactéries impliquées.\n3. Nodosités racinaires.',correction:'1. Conversion N₂ atmosphérique → NH₃ puis NO₃⁻ assimilable\n2. Rhizobium (symbiose) · Azotobacter (libre) · Cyanobactéries\n3. Renflements racinaires avec Rhizobium en symbiose',notions:['Fixation azote']},
      {id:'SV7-08',difficulte:2,titre:'Agriculture biologique',enonce:'1. Définir.\n2. Produits interdits.\n3. Critiques et limites.',correction:'1. Exclut intrants synthétiques\n2. Engrais chimiques · pesticides · OGM · antibiotiques préventifs\n3. Rendements −20-25% · prix élevé · pas 0 pesticide (cuivre = polluant)',notions:['Agriculture bio']},
      {id:'SV7-09',difficulte:2,titre:'Nourrir 10 milliards d\'humains',enonce:'1. Défis.\n2. Insectes comme protéines.\n3. Gaspillage alimentaire.',correction:'1. +60% production sans + de terres + réchauffement climatique\n2. ×10 moins de terres · ×100 moins d\'eau\n3. 1/3 de la nourriture gaspillée → réduire portions · valoriser invendus',notions:['Sécurité alimentaire']},
      {id:'SV7-10',difficulte:2,titre:'Agroforesterie',enonce:'1. Définir.\n2. 4 avantages.\n3. Différence avec sylviculture.',correction:'1. Association arbres + cultures/élevage\n2. Brise-vent · ombre · matière organique · biodiversité · CO₂\n3. Sylviculture = forêt uniquement. Agroforesterie = double production',notions:['Agroforesterie']},
      {id:'SV7-11',difficulte:2,titre:'Pesticides et abeilles',enonce:'1. Néonicotinoïde.\n2. Problème pour abeilles.\n3. Interdiction France.',correction:'1. Insecticide systémique présent dans pollen et nectar\n2. Désorientation · perte mémoire · mort des colonies\n3. Interdits depuis 2018 (hors serres closes)',notions:['Pesticides']},
      {id:'SV7-12',difficulte:2,titre:'Irrigation et eau',enonce:'Agriculture = 70% eau mondiale.\n1. Systèmes et efficacité.\n2. Problèmes irrigation excessive.\n3. Solutions.',correction:'1. Aspersion 60-70% · Pivot 70-80% · Goutte-à-goutte 90-95%\n2. Salinisation · assèchement nappes\n3. Goutte-à-goutte + capteurs · variétés résistantes sécheresse',notions:['Irrigation']},
      {id:'SV7-13',difficulte:3,titre:'Calcul bilan azoté',enonce:'8 t grain (2% N) + 8 t paille (0,5% N). Apport : 150 kg N/ha.\n1. Export total N.\n2. Bilan azoté.\n3. Interprétation.',correction:'1. N grain : 160 kg. N paille : 40 kg. Total = 200 kg\n2. Bilan = 150 − 200 = −50 kg N/ha (déficit)\n3. Sol perd 50 kg N/ha/an → baisse fertilité → insoutenable',notions:['Bilan azoté']},
      {id:'SV7-14',difficulte:2,titre:'Agriculture de précision',enonce:'1. Définir.\n2. Technologies.\n3. Bénéfices environnementaux.',correction:'1. Optimiser intrants selon variabilité spatiale\n2. GPS · drones · capteurs sols · IA · robots\n3. −15-30% pesticides · −10-20% engrais',notions:['Agriculture précision']},
      {id:'SV7-15',difficulte:2,titre:'Lutte biologique',enonce:'1. Définir.\n2. 3 exemples.\n3. Avantages et risques.',correction:'1. Organismes vivants pour réduire ravageurs\n2. Coccinelle/pucerons · Trichogramme/pyrales · Bt/chenilles\n3. Avantages : pas résidus chimiques. Risques : espèce peut devenir invasive',notions:['Lutte biologique']},
      {id:'SV7-16',difficulte:2,titre:'Pollinisation et agriculture',enonce:'75% espèces cultivées dépendent des pollinisateurs.\n1. 5 espèces pollinisatrices.\n2. Valeur France.\n3. Comment protéger.',correction:'1. Abeille mellifère · Bourdon · Papillons · Syrphes · Coléoptères\n2. 2,3 milliards €/an\n3. Bandes fleuries · réduire insecticides · haies',notions:['Pollinisation']},
      {id:'SV7-17',difficulte:3,titre:'OGM — débat',enonce:'1. Définir OGM et transgénèse.\n2. Arguments en faveur.\n3. Arguments contre.',correction:'1. Organisme à génome modifié par gène étranger (Agrobacterium · CRISPR)\n2. Résistance insectes · tolérance sécheresse · enrichissement nutritionnel\n3. Brevets semenciers · flux de gènes · principe de précaution',notions:['OGM']},
      {id:'SV7-18',difficulte:2,titre:'Économie circulaire en agriculture',enonce:'1. Définir.\n2. Exemple agricole.\n3. Méthaniseur.',correction:'1. Déchets d\'un processus = ressources d\'un autre\n2. Lisier → compost → engrais → céréales → alimentation porcs\n3. Fermentation anaérobie → biogaz + digestat (engrais)',notions:['Économie circulaire']},
      {id:'SV7-19',difficulte:3,titre:'Empreinte carbone des protéines',enonce:'Bœuf 60 · Poulet 11 · Tofu 3,5 · Lentilles 1,2 kg CO₂/kg protéines.\n1. Ratio bœuf/lentilles.\n2. Recommandation.\n3. Obstacles.',correction:'1. 60/1,2 = 50 → bœuf émet 50× plus\n2. Réduire viande rouge · légumineuses + volaille\n3. Habitudes culturelles · lobby élevage · coût substituts',notions:['Empreinte carbone']},
      {id:'SV7-20',difficulte:3,titre:'Bilan agriculture et développement durable',enonce:'1. Agriculture et émissions GES.\n2. Comment atténuer.\n3. Définir agroécologie.',correction:'1. ~20-25% GES : CH₄ (élevage) · N₂O (engrais) · CO₂ (déforestation)\n2. Agroforesterie · semis direct · méthanisation · réduire élevage bovin\n3. Application des principes écologiques à l\'agriculture',notions:['Agroécologie']},
    ]
  },
  {
    id:'fecondation-puberte-seconde-svt', numero:8,
    titre:'De la fécondation à la puberté',
    sousTitre:'Gamètes · Fécondation · Développement · Puberté · Hormones',
    icon:'👶', color:'#ec4899',
    notions:['Gamètes','Fécondation','Embryon','Puberté','Hormones sexuelles'],
    exercices:[
      {id:'SV8-01',difficulte:1,titre:'Les gamètes',enonce:'1. Définir gamète.\n2. Comparer spermatozoïde et ovule.\n3. Chromosomes dans chaque gamète humain.',correction:'1. Cellule reproductrice haploïde (n) issue de la méiose\n2. Spz : 5µm · mobile · 300 M/éjaculat. Ovule : 120µm · immobile · 1/cycle\n3. n = 23 chromosomes',notions:['Gamètes']},
      {id:'SV8-02',difficulte:1,titre:'La fécondation',enonce:'1. Définir.\n2. Où se déroule-t-elle.\n3. Chromosomes du zygote.',correction:'1. Fusion spermatozoïde + ovocyte → zygote diploïde (2n)\n2. Trompe de Fallope (12-24h après ovulation)\n3. 2n = 46 chromosomes',notions:['Fécondation']},
      {id:'SV8-03',difficulte:1,titre:'Détermination du sexe',enonce:'1. Chromosomes sexuels homme et femme.\n2. Quel gamète détermine le sexe.\n3. Probabilité garçon.',correction:'1. Homme : XY. Femme : XX\n2. Le spermatozoïde (X → fille · Y → garçon) → le père détermine\n3. P(garçon) = 50%',notions:['Chromosomes sexuels']},
      {id:'SV8-04',difficulte:1,titre:'Développement embryonnaire',enonce:'8 étapes clés de la fécondation à la naissance.',correction:'1. Fécondation (J0) → zygote\n2. Segmentation → morula\n3. Blastocyste (J5)\n4. Nidation (J7-J10)\n5. Embryon (S3-S8) → gastrulation → organogenèse\n6. Fœtus (S9→)\n7. Croissance fœtale\n8. Naissance (S40)',notions:['Développement']},
      {id:'SV8-05',difficulte:1,titre:'La puberté',enonce:'1. Définir.\n2. Âge moyen fille et garçon.\n3. 4 caractères sexuels secondaires chez chacun.',correction:'1. Maturation sexuelle permettant la reproduction\n2. Fille : 10-12 ans. Garçon : 11-13 ans\n3. Fille : seins · pilosité · hanches · règles. Garçon : pilosité · voix · muscles · spermarche',notions:['Puberté']},
      {id:'SV8-06',difficulte:2,titre:'Hormones sexuelles',enonce:'1. 3 hormones et sources.\n2. Rôle testostérone.\n3. Rôle œstrogènes à la puberté.',correction:'1. Testostérone (testicules) · Œstrogènes (ovaires) · Progestérone (corps jaune)\n2. Caractères secondaires masculins + spermatogenèse\n3. Seins · hanches · pilosité · croissance',notions:['Hormones']},
      {id:'SV8-07',difficulte:2,titre:'Appareil génital masculin',enonce:'1. Organes principaux.\n2. Où produit les spz.\n3. Rôle prostate.',correction:'1. Testicules · épididyme · canal déférent · vésicules séminales · prostate · urètre · pénis\n2. Tubes séminifères des testicules\n3. Liquide basique neutralisant l\'acidité + active les spermatozoïdes',notions:['Appareil masculin']},
      {id:'SV8-08',difficulte:2,titre:'Appareil génital féminin',enonce:'1. Organes.\n2. Trajet de l\'ovule.\n3. Lieu exact de la fécondation.',correction:'1. Ovaires · trompes · utérus · col · vagin · vulve\n2. Ovaire → pavillon trompe → trompe → utérus\n3. Tiers externe de la trompe (ampoule tubaire)',notions:['Appareil féminin']},
      {id:'SV8-09',difficulte:2,titre:'Contraception',enonce:'1. Définir.\n2. 4 méthodes et mécanismes.\n3. Contraception d\'urgence.',correction:'1. Méthodes pour éviter une grossesse non désirée\n2. Pilule (bloque ovulation) · préservatif (barrière) · DIU · implant\n3. Lévonorgestrel dans 72h → bloque/retarde ovulation (pas abortif)',notions:['Contraception']},
      {id:'SV8-10',difficulte:2,titre:'IST',enonce:'1. 4 IST et agents.\n2. Seul moyen de protection contre IST.\n3. Dépistage.',correction:'1. VIH (rétrovirus) · Chlamydia (bactérie) · Herpès (VHS-2) · Syphilis (Treponema)\n2. Préservatif\n3. Test biologique pour détecter une IST avant les symptômes',notions:['IST']},
      {id:'SV8-11',difficulte:2,titre:'Cycle menstruel',enonce:'1. Durée moyenne.\n2. Phases principales.\n3. Quand a lieu l\'ovulation.',correction:'1. 28 jours (variable 21-35 j)\n2. Menstruelle (J1-J5) → proliférative (J5-J14) → sécrétoire (J14-J28)\n3. J14 environ (pic LH)',notions:['Cycle menstruel']},
      {id:'SV8-12',difficulte:2,titre:'Grossesse et nidation',enonce:'1. Définir nidation.\n2. Organe qui se développe après.\n3. Rôle du placenta.',correction:'1. Implantation du blastocyste dans l\'endomètre (J7-J10)\n2. Le placenta (du trophoblaste)\n3. Échanges O₂ + nutriments + déchets · sécrète hormones (HCG, progestérone)',notions:['Nidation']},
      {id:'SV8-13',difficulte:2,titre:'Spermatogenèse',enonce:'1. Définir.\n2. Lieu et durée.\n3. Étapes principales.',correction:'1. Production de spermatozoïdes\n2. Tubes séminifères des testicules · ~74 jours\n3. Multiplication (mitoses) → accroissement → maturation (méiose) → spermiogenèse',notions:['Spermatogenèse']},
      {id:'SV8-14',difficulte:2,titre:'Régulation hormonale masculine',enonce:'1. Axe hormonal contrôlant la testostérone.\n2. Rétrocontrôle négatif.\n3. Rôle LH et FSH.',correction:'1. Hypothalamus (GnRH) → Hypophyse (LH+FSH) → Testicules\n2. Testostérone inhibe hypothalamus et hypophyse\n3. LH → cellules de Leydig → testostérone. FSH → spermatogenèse',notions:['Régulation hormonale']},
      {id:'SV8-15',difficulte:3,titre:'PMA',enonce:'1. Types de PMA.\n2. Indications.\n3. Aspect éthique.',correction:'1. IAD · FIV · ICSI · GIFT\n2. Stérilité masculine · tubaire · infertilité inexpliquée\n3. Sélection embryonnaire (DPI) · congélation ovocytes · GPA (illégale en France)',notions:['PMA']},
      {id:'SV8-16',difficulte:2,titre:'Prévention grossesses non désirées',enonce:'1. Causes échec contraceptif.\n2. Qu\'est-ce que l\'IVG.\n3. Délai légal en France.',correction:'1. Oubli pilule · préservatif mal utilisé · interaction médicamenteuse\n2. Interruption Volontaire de Grossesse (droit fondamental — loi Veil 1975)\n3. 14 semaines de grossesse depuis 2022',notions:['IVG']},
      {id:'SV8-17',difficulte:2,titre:'Développement fœtal — jalons',enonce:'Âge (SA) pour :\n1. Battements cardiaques.\n2. Sexe identifiable.\n3. Viabilité hors utérus.',correction:'1. SA 6-7\n2. SA 20-22 (échographie morphologique)\n3. ~SA 24-25 (poumons insuffisamment matures avant)',notions:['Développement fœtal']},
      {id:'SV8-18',difficulte:3,titre:'Puberté précoce',enonce:'1. Définir.\n2. Causes possibles.\n3. Conséquences si non traitée.',correction:'1. Avant 8 ans (fille) ou 9 ans (garçon)\n2. Idiopathique · perturbateurs endocriniens · tumeurs · adoption internationale\n3. Petite taille adulte · troubles psychologiques · risque surpoids',notions:['Puberté précoce']},
      {id:'SV8-19',difficulte:2,titre:'Anatomie de la grossesse',enonce:'1. Liquide amniotique.\n2. Rôle du cordon ombilical.\n3. Accouchement.',correction:'1. Entoure le fœtus → protection mécanique + thermique + développement poumons\n2. Relie fœtus au placenta → O₂ + nutriments + déchets\n3. Expulsion fœtus + placenta (ocytocine → contractions)',notions:['Grossesse']},
      {id:'SV8-20',difficulte:3,titre:'Bilan reproduction humaine',enonce:'Comment les hormones coordonnent-elles la reproduction de la puberté à la grossesse ?',correction:'Puberté : GnRH → LH/FSH → gonades → hormones sexuelles\nCycle féminin : FSH → follicule → œstrogènes → pic LH → ovulation → corps jaune → progestérone\nFécondation : spz + ovocyte → zygote\nGrossesse : HCG maintient corps jaune → progestérone → endomètre\nTout coordonné par rétrocontrôles hormonaux précis',notions:['Bilan']},
    ]
  },
  {
    id:'cerveau-sante-seconde-svt', numero:9,
    titre:'Hormones, Cerveau & Santé',
    sousTitre:'Microbiote · Agents pathogènes · VIH · Immunité · Hormones · Cerveau',
    icon:'🧠', color:'#8b5cf6',
    notions:['Microbiote','Agent pathogène','VIH','Immunité','Cerveau'],
    exercices:[
      {id:'SV9-01',difficulte:1,titre:'Agents pathogènes — types',enonce:'1. Définir agent pathogène.\n2. Les 4 types.\n3. Exemple pour chacun.',correction:'1. Organisme capable de provoquer une maladie\n2. Virus · Bactéries · Parasites · Champignons\n3. VIH · streptocoque · Plasmodium (paludisme) · Candida (mycose)',notions:['Agents pathogènes']},
      {id:'SV9-02',difficulte:1,titre:'Microbiote humain',enonce:'1. Définir.\n2. Principal microbiote.\n3. Rôles essentiels.',correction:'1. Ensemble des micro-organismes en symbiose sur/dans le corps\n2. Intestin (~38 000 milliards de bactéries, 1,5-2 kg)\n3. Digestion · immunité · protection (effet barrière) · vitamines K et B12',notions:['Microbiote']},
      {id:'SV9-03',difficulte:1,titre:'VIH et SIDA',enonce:'1. Distinguer VIH et SIDA.\n2. Modes de transmission.\n3. Cellules ciblées.',correction:'1. VIH = virus. SIDA = stade avancé de l\'infection (immunodépression profonde)\n2. Relations sexuelles non protégées · sang · mère-enfant\n3. Lymphocytes T CD4 (LT auxiliaires)',notions:['VIH']},
      {id:'SV9-04',difficulte:1,titre:'Maladies vectorielles',enonce:'1. Définir.\n2. Paludisme : agent, vecteur, symptômes.\n3. 2 autres maladies vectorielles.',correction:'1. Maladie transmise par un vecteur (insecte ou arthropode)\n2. Plasmodium falciparum · Anophèles femelle · fièvre, frissons, anémie\n3. Dengue (Aedes) · Lyme (tique)',notions:['Maladies vectorielles']},
      {id:'SV9-05',difficulte:1,titre:'Immunité innée',enonce:'1. Définir.\n2. Les 3 barrières naturelles.\n3. Phagocytose.',correction:'1. Première ligne de défense, immédiate, non spécifique\n2. Peau · Muqueuses (mucus) · Sécrétions (lysozyme)\n3. Ingestion et destruction des agents pathogènes par les phagocytes',notions:['Immunité innée']},
      {id:'SV9-06',difficulte:2,titre:'Inflammation',enonce:'1. Définir.\n2. Les 4 signes cliniques.\n3. Mécanisme cellulaire.',correction:'1. Réponse locale et immédiate à une agression\n2. Rougeur · chaleur · œdème · douleur\n3. Histamine + cytokines → vasodilatation → afflux phagocytes → phagocytose',notions:['Inflammation']},
      {id:'SV9-07',difficulte:2,titre:'Axe hormonal de la reproduction',enonce:'1. GnRH, LH, FSH : sources et rôles.\n2. Axe hypothalamo-hypophysaire.\n3. Rétrocontrôle négatif.',correction:'1. GnRH : hypothalamus. LH+FSH : hypophyse → stimulent gonades\n2. Hypothalamus → GnRH → Hypophyse → LH+FSH → Gonades → hormones\n3. Hormones sexuelles inhibent hypothalamus et hypophyse',notions:['Axe hormonal']},
      {id:'SV9-08',difficulte:2,titre:'Cerveau et comportements',enonce:'1. Principales régions cérébrales et fonctions.\n2. Plasticité cérébrale.\n3. Lien hormones sexuelles et cerveau.',correction:'1. Cortex : raisonnement. Hippocampe : mémoire. Amygdale : émotions. Hypothalamus : hormones\n2. Capacité du cerveau à se modifier en réponse à l\'expérience\n3. Œstrogènes et testostérone influencent développement cérébral et comportements',notions:['Cerveau']},
      {id:'SV9-09',difficulte:2,titre:'Dysbiose du microbiote',enonce:'1. Définir dysbiose.\n2. Causes possibles.\n3. Maladies associées.',correction:'1. Déséquilibre de la composition du microbiote\n2. Antibiotiques · alimentation pauvre en fibres · stress · infections\n3. MICI · obésité · diabète type 2 · dépression · allergies',notions:['Dysbiose']},
      {id:'SV9-10',difficulte:2,titre:'Prévention des maladies infectieuses',enonce:'1. Prévention primaire, secondaire, tertiaire.\n2. Exemple pour le VIH.\n3. Qu\'est-ce que la PrEP.',correction:'1. Primaire : éviter (avant). Secondaire : dépistage (pendant). Tertiaire : limiter séquelles\n2. Préservatif · dépistage régulier · traitement antirétroviral\n3. Traitement préventif chez personnes à risque (réduit risque infection >95%)',notions:['Prévention']},
      {id:'SV9-11',difficulte:2,titre:'Hygiène et santé',enonce:'1. Pourquoi se laver les mains est-il si efficace.\n2. Comment les antibiotiques agissent.\n3. Pourquoi pas d\'antibiotiques contre un virus.',correction:'1. Élimine mécaniquement les micro-organismes → rompt la chaîne de transmission\n2. Détruisent/inhibent bactéries (cibles : paroi, ribosomes, ADN bactériens)\n3. Aucun effet sur virus → inefficaces + favorisent résistances inutilement',notions:['Hygiène']},
      {id:'SV9-12',difficulte:2,titre:'Alcool et santé',enonce:'1. Effets de l\'alcool sur le SN.\n2. Usage nocif.\n3. Effets sur le fœtus.',correction:'1. Potentialise GABA + inhibe glutamate → désinhibition · troubles coordination\n2. >21 verres/semaine (homme) ou >14 (femme)\n3. SAF (Syndrome Alcoolisation Fœtale) → retard mental · malformations · aucune dose sûre',notions:['Alcool']},
      {id:'SV9-13',difficulte:2,titre:'Perturbateurs endocriniens',enonce:'1. Définir.\n2. Exemples et sources.\n3. Effets sur la santé.',correction:'1. Substance interférant avec le système hormonal\n2. Bisphénol A (plastiques) · Phtalates (cosmétiques) · Pesticides organochlorés\n3. Puberté perturbée · infertilité · cancers hormonaux · obésité',notions:['Perturbateurs endocriniens']},
      {id:'SV9-14',difficulte:3,titre:'Antibiorésistance',enonce:'1. Définir.\n2. Mécanisme d\'apparition.\n3. Solutions.',correction:'1. Capacité d\'une bactérie à survivre en présence d\'un antibiotique\n2. Mutation → bactérie survit → sélection darwinienne → résistance se répand\n3. Antibiothérapie ciblée · dose et durée respectées · hygiène hospitalière · nouveaux antibiotiques',notions:['Antibiorésistance']},
      {id:'SV9-15',difficulte:2,titre:'Vaccination',enonce:'1. Principe.\n2. Pourquoi des rappels.\n3. Immunité collective.',correction:'1. Antigène inoffensif → réponse immunitaire → cellules mémoires → protection\n2. Immunité diminue → rappel renforce la mémoire immunologique\n3. 70-95% de personnes immunisées → virus ne circule plus → protection des non vaccinés',notions:['Vaccination']},
      {id:'SV9-16',difficulte:2,titre:'Santé mentale',enonce:'1. Définir (OMS).\n2. Facteurs favorisants.\n3. Lien stress chronique et santé physique.',correction:'1. État de bien-être permettant de réaliser son potentiel\n2. Relations sociales · activité physique · sommeil · sens des activités\n3. Cortisol élevé → immunosuppression · HTA · diabète type 2 · dépression',notions:['Santé mentale']},
      {id:'SV9-17',difficulte:2,titre:'Addictions et cerveau',enonce:'1. Mécanisme neurobiologique.\n2. Dépendance physique vs psychologique.\n3. Facteurs de vulnérabilité.',correction:'1. Drogues détournent le circuit de récompense (dopamine) → neuroadaptation → dépendance\n2. Physique : corps a besoin (symptômes manque physiques). Psychologique : cerveau veut (anxiété, dépression)\n3. Génétique · âge de début précoce · stress · troubles psychiatriques',notions:['Addiction']},
      {id:'SV9-18',difficulte:3,titre:'COVID-19 et pandémie',enonce:'1. Qu\'est-ce que le SARS-CoV-2.\n2. Pourquoi pandémie et non épidémie.\n3. Mécanismes d\'entrée dans les cellules.',correction:'1. Coronavirus à ARN enveloppé → cause COVID-19\n2. Pandémie : épidémie mondiale (>1 continent). Transmission facile + pas d\'immunité + mondialisation\n3. Protéine Spike → récepteur ACE2 des cellules (poumons, cœur...) → fusion → entrée ARN viral',notions:['COVID-19']},
      {id:'SV9-19',difficulte:2,titre:'Alimentation et santé',enonce:'1. Grands groupes de nutriments et rôles.\n2. Conséquences excès sucres rapides.\n3. Lien alimentation et microbiote.',correction:'1. Glucides (énergie rapide) · Lipides (énergie longue + membranes) · Protéines (construction) · Vitamines · Eau + fibres\n2. Obésité · diabète type 2 · caries · dysbiose microbiote\n3. Fibres nourrissent bactéries bénéfiques. Alimentation pauvre → dysbiose',notions:['Alimentation']},
      {id:'SV9-20',difficulte:3,titre:'Bilan santé et société',enonce:'1. Facteurs de santé modifiables.\n2. Facteurs non modifiables.\n3. Concept "One Health".',correction:'1. Tabac · alcool · alimentation · activité physique · sommeil · comportements sexuels\n2. Âge · sexe · génétique · antécédents familiaux\n3. Santé humaine + animale + environnementale indissociables. Ex : déforestation → contact animaux sauvages → émergence virus → pandémie',notions:['One Health']},
    ]
  },
]

